				tempLog = inDto[x].toString();
				
				//삭제 KEY SETTING
							
				//적치열번호
				paraRec.setField("YD_STK_COL_NO", inDto[x].getField("YD_STK_COL_NO"));
				
				//야드 구분
				paraRec.setField("YD_GP", 		inDto[x].getField("YD_GP"));
				
				//동구분
				paraRec.setField("YD_BAY_GP", 	inDto[x].getField("YD_BAY_GP"));
				
				//설비구분 
