	/**
	 * 동/SPAN/열별 모니터링 수정
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String[] updPlateYdDongSpanLineRef(JDTORecord[] inDto) throws DAOException {
		int intRtnVal 		= 0;
		String szMsg		= "";
		String[] szRtnMsg 	= null;
		String szMethodName = "updPlateYdDongSpanLineRef";
		String szOperationName = "동/SPAN/열별 모니터링 수정";
	
		JDTORecord  recPara   	= JDTORecordFactory.getInstance().create();		
		YdStkBedDao ydStkBedDao = new YdStkBedDao();
		
		szRtnMsg = new String[inDto.length];
		try {
			
			for(int x=0;x<inDto.length;x++){
				//설비 ID 및 수정항목 세팅 
				recPara.setField("YD_STK_COL_GP",          yddatautil.setDataDefault(inDto[x].getField("YD_STK_COL_GP"),  ""));
				recPara.setField("YD_STK_BED_NO",          yddatautil.setDataDefault(inDto[x].getField("YD_STK_BED_NO"),  ""));
				recPara.setField("YD_STK_BED_ACT_STAT",    yddatautil.setDataDefault(inDto[x].getField("YD_STK_BED_ACT_STAT"),  ""));
				//수정
				recPara.setField("MODIFIER",   			   yddatautil.setDataDefault(inDto[x].getFieldString("YD_USER_ID"),""));
			
				ydUtils.displayRecord(szOperationName, recPara);
				
				// 적치 BED 관련 수정 
				intRtnVal = ydStkBedDao.updYdStkbed(recPara, 0);
				
				if(intRtnVal > 0){
		        	szRtnMsg[x] = YdConstant.RETN_CD_SUCCESS;
		        	szMsg = "[JSP Session] 처리 RETURN VALUE [ " + szRtnMsg[x] + " ]\n";
		        	szMsg += "[JSP Session] 동/SPAN/열별 모니터링 수정 - 해당 야드 적치열 구분[" + yddatautil.setDataDefault(inDto[x].getFieldString("YD_STK_COL_GP"),"") + "], 야드적치BED번호[" + yddatautil.setDataDefault(inDto[x].getField("YD_STK_BED_NO"),"") + "] " 
		        	      + "의 야드 적치 BED 활성상태[" + yddatautil.setDataDefault(inDto[x].getField("YD_STK_BED_ACT_STAT"),"") + "]가 성공적으로 수정되었습니다!";
		        	      
		        	ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		        	
		        }else if(intRtnVal == 0){
		        	szRtnMsg[x] = YdConstant.RETN_CD_NOTEXIST;
		        	szMsg = "[JSP Session] 동/SPAN/열별 모니터링 수정 - 해당 야드 적치열 구분[" + inDto[x].getFieldString("YD_STK_COL_GP") + "], 야드적치BED번호[" + inDto[x].getField("YD_STK_BED_NO") + "]가 존재하지 않습니다!";
		        	ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					throw new DAOException(szRtnMsg[x]);
					
		        }else if (intRtnVal < 0) {
					if (intRtnVal == -1) {
						szMsg = "routine error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "parameter error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}
				} // end of if
			}			
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return szRtnMsg;
	}
	
