	public void delPlateYdMapStkCol(JDTORecord[] inDto) throws DAOException {
		int intRtnVal = 0;
		String szMsg="";
		String szMethodName="delPlateYdMapStkCol";		
	
		JDTORecord recPara = JDTORecordFactory.getInstance().create();
		YdStkColDao ydStkColDao = new YdStkColDao();
		YdStkLyrDao ydStkLyrDao = new YdStkLyrDao();
			
		try {
			for(int x=0;x<inDto.length;x++){
				//실제 DB 적치열 정보 유무 확인
				recPara   = JDTORecordFactory.getInstance().create();
				recPara.setField("YD_STK_COL_GP",         		yddatautil.setDataDefault(inDto[x].getField("YD_STK_COL_GP"),  	""));
				JDTORecordSet outRecSet = JDTORecordFactory.getInstance().createRecordSet("YD");
				
				intRtnVal = ydStkLyrDao.getYdStklyr(recPara, outRecSet, 68);
				
				if(intRtnVal > 0 ) return;
				
				recPara.setField("YD_STK_COL_GP",     	yddatautil.setDataDefault(inDto[x].getFieldString("YD_STK_COL_GP"),		""));
				recPara.setField("DEL_YN",    			"Y");
				recPara.setField("MODIFIER",   			yddatautil.setDataDefault(inDto[x].getField("MODIFIER"),				""));
				
		        intRtnVal = ydStkColDao.updYdStkcol(recPara,0);
		        
				if (intRtnVal < 0) {
					if (intRtnVal == -1) {
						szMsg = "routine error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "parameter error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}					
				} // end of if
			}
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally{
		}		
	}	// end of delPlateYdMapStkCol
	
