	/**
	 * 저장속성그룹과 저장속성을 연결/해제
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 */
	public String procMatchORUnMatchStkChar(JDTORecord [] inDto) {
		String szRtnMsg = YdConstant.RETN_CD_SUCCESS;
		int intRtnVal 			= 0;
		String szMsg			= " ";
		String szMethodName		= "procMatchORUnMatchStkChar";
		String szOperationName	= "저장속성Match/UnMatch";
		
		String szMatchType		= null;
		String szYD_STRCHAR_ID	= null;
		JDTORecord recPara = JDTORecordFactory.getInstance().create();
		YdStrCharDao ydStrCharDao = new YdStrCharDao();
			
		try {
			szMatchType = yddatautil.setDataDefault(inDto[0].getField("MATCH_TYPE"),		"");
			for(int x=0;x<inDto.length;x++){
				szYD_STRCHAR_ID = yddatautil.setDataDefault(inDto[x].getField("YD_STRCHAR_ID"),		"");
				szMsg = "[JSP Session : "+ szOperationName +"] 저장속성["+szYD_STRCHAR_ID+"] " + (szMatchType.equals("M") ? "Match" : (szMatchType.equals("U") ? "UnMatch" : "삭제")) + " 시작 - ";
				ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
				
				ydUtils.displayRecord(szOperationName, inDto[x]);
				
				recPara.setField("YD_STRCHAR_ID",     	szYD_STRCHAR_ID);
				if( szMatchType.equals("M") ) {						//MATCH
					recPara.setField("YD_STRCHAR_GRP_CD",   yddatautil.setDataDefault(inDto[x].getField("YD_STRCHAR_GRP_CD"),	""));
				}else if( szMatchType.equals("U") ) {				//UNMATCH
					recPara.setField("YD_STRCHAR_GRP_CD",   "");
				}
				recPara.setField("MODIFIER",   			yddatautil.setDataDefault(inDto[x].getField("YD_USER_ID"),			""));
				if( szMatchType.equals("M") || szMatchType.equals("U") ) {
					intRtnVal = ydStrCharDao.updYdStrchar(recPara,0);
				}else if( szMatchType.equals("D") ) {
					intRtnVal = ydStrCharDao.delYdStrchar(recPara);
				}
		        
				if (intRtnVal < 0) {
					szMsg = "[JSP Session : "+ szOperationName +"] 오류발생[1] - 반환값 : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.ERROR);					
				}else if( intRtnVal == 0 ) {
					szMsg = "[JSP Session : "+ szOperationName +"] 오류발생[2] - 저장속성["+szYD_STRCHAR_ID+"]이 존재하지 않습니다. : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.ERROR);
				}else{
					szMsg = "[JSP Session : "+ szOperationName +"] 저장속성["+szYD_STRCHAR_ID+"]이 성공적으로 " + (szMatchType.equals("M") ? "Match" : (szMatchType.equals("U") ? "UnMatch" : "삭제")) + "되었습니다.";
					ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
				}
			}
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally{
		}		
		return szRtnMsg;
	}	// end of procMatchORUnMatchStkChar
	
	
