	public JDTORecord updPlateYdStrChar(JDTORecord [] inDto) {
		
		String szRtnMsg = YdConstant.RETN_CD_SUCCESS;
		
		int intRtnVal = 0;
		String szMsg="";
		String szMethodName="updPlateYdStrChar";		
		
		String szYD_STRCHAR_GRP     = "";
		String szCUST_CD			= "";
		String szDETAIL_ARR_CD		= "";
		String szORD_GP 			= "";
		String szDELIVER_TERM_CD	= "";
		String szDELIVER_TERM_CD1	= "";
		String szORD_NO				= "";
		String szYD_USER_ID			= "";
		String szREPR				= "";
		String szDEMANDER_CD		= "";
		
		String sORD_NO 			= "";
		String sORD_DTL 		= "";
		String sORD_CONV_W 		= "";
		String sORD_CONV_LEN 	= "";
		String sORD_EA 			= ""; 
		String sORD_CONV_T	  	= ""; 
		String sQueryId			= "";
		
		JDTORecordSet rsResult1		= null;
		
		JDTORecord outRecord 		= JDTORecordFactory.getInstance().create();
		JDTORecord recTemp			= JDTORecordFactory.getInstance().create();
		JDTORecord recPara1			= null;
		JDTORecord recPara 			= null;
		
		YdStrCharDao ydStrCharDao 	= new YdStrCharDao();
		YdStrGtrDao  dao 			= new YdStrGtrDao();
		YdPlateCommDAO commDao		= new YdPlateCommDAO();
		
		try {
			for(int inx = 0; inx < inDto.length; inx++){
				/*
				 * 1.미매핑 해당고객사/상세착지 정보를 저장속성그룹에 셋팅하기
				 *   - 고객사/상세착지 정보 등록
				 *   - 대형/일반 여부
				 */
				szYD_STRCHAR_GRP    = yddatautil.setDataDefault(inDto[inx].getField("YD_STRCHAR_GRP"),	"");
				szCUST_CD			= yddatautil.setDataDefault(inDto[inx].getField("CUST_CD"),	"");
				szDETAIL_ARR_CD		= yddatautil.setDataDefault(inDto[inx].getField("DETAIL_ARR_CD"),	"");
				szORD_GP 			= yddatautil.setDataDefault(inDto[inx].getField("ORD_GP"),	"");
				szDELIVER_TERM_CD1	= yddatautil.setDataDefault(inDto[inx].getField("DELIVER_TERM_CD"),	"");
				szORD_NO			= yddatautil.setDataDefault(inDto[inx].getField("ORD_NO"),	"");
				
				if (szDELIVER_TERM_CD1.equals("")) {
					szDELIVER_TERM_CD = "1";
				}else {
					szDELIVER_TERM_CD =szDELIVER_TERM_CD1.substring(0, 1);
				}
				
				szYD_USER_ID		= yddatautil.setDataDefault(inDto[inx].getField("YD_USER_ID"),	"");

				szREPR 				= yddatautil.setDataDefault(inDto[inx].getField("REPR"),	"");
				
				if(szREPR.equals("Y")) { //대형
					szDEMANDER_CD 	= yddatautil.setDataDefault(inDto[inx].getField("CUST_CD"),	"");
				}
				
				//동일대표,일반,목적지  CHECK				
				rsResult1 = JDTORecordFactory.getInstance().createRecordSet("");
				recPara1 = JDTORecordFactory.getInstance().create();
				recPara1.setField("REPR"			, "2");	// 일반으로 체크한다(고객사/상세착지 정보가 있는지 확인)
				recPara1.setField("DETAIL_ARR_CD"	, szDETAIL_ARR_CD);
				recPara1.setField("CUST_CD"			, szCUST_CD);
				recPara1.setField("DEMANDER_CD"		, szCUST_CD);
				
				/*com.inisteel.cim.yd.dao.ydstrchardao.YdStrcharDao.getYdStrcharByDetatilArrCd*/
				intRtnVal = ydStrCharDao.getYdStrchar(recPara1, rsResult1, 301);
					
				if( intRtnVal == 0 ) {
					
					recPara = JDTORecordFactory.getInstance().create();
					recPara.setField("YD_GP",				"T"); 
					recPara.setField("YD_STRCHAR_GRP_CD",   szYD_STRCHAR_GRP);
					recPara.setField("DEST_CD",   			szDETAIL_ARR_CD.substring(0,3));
					recPara.setField("CUST_CD",   			szCUST_CD);
					recPara.setField("DEMANDER_CD",   		szDEMANDER_CD);
					recPara.setField("ORD_GP",   			szORD_GP);
					recPara.setField("DELIVER_TERM_CD",   	szDELIVER_TERM_CD);
					recPara.setField("REGISTER",   			szYD_USER_ID);
					recPara.setField("ORD_NO",				"");
					recPara.setField("ORD_DTL",				"");
					recPara.setField("DETAIL_ARR_CD",		szDETAIL_ARR_CD);
				
					intRtnVal = ydStrCharDao.insYdStrchar(recPara);
					if (intRtnVal <= 0) {
						szMsg = "[JSP Session : "+ szMethodName +"] 오류발생[1] - 반환값 : " + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.ERROR);
						szRtnMsg = szMsg; 
					}else{
						szMsg = "[JSP Session : "+ szMethodName +"] 저장속성그룹["+szYD_STRCHAR_GRP+"]  고객사["+szCUST_CD+"] 목적지["+szDETAIL_ARR_CD+"]이 성공적으로 등록되었습니다.";
						ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
					}
				} else {
					
					rsResult1.first();
					recTemp = rsResult1.getRecord();
					
					szYD_STRCHAR_GRP = ydDaoUtils.paraRecChkNull(recTemp, "YD_STRCHAR_GRP_CD");

					szMsg = szYD_STRCHAR_GRP+" 저장속성으로 동일 정보가 있습니다.삭제후 처리 하세요";
					ydUtils.putLog(szMethodName, szMethodName, szMsg, YdConstant.ERROR);
					outRecord.setField("RTN_CD" 		, "0");	
					outRecord.setField("RTN_MSG" 		, szMsg);
					
					return outRecord;
				}
				
				if("Y".equals(szREPR)){
					intRtnVal = dao.updYdStrchar(recPara,1); 
				}else{
					intRtnVal = dao.updYdStrchar(recPara,2);
				}
				
				/*
				 * 2. 미매핑 해당고객사/상세착지 주문정보에 해당하는 파일링코드 셋팅
				 * 3. 미매핑 해당고객사/상세착지 주문정보에 해당하는 1후판용 1차 저장계획(입고예정위치) 셋팅(주문투입정보[PTYDJ004] 확인)  
				 */
				JDTORecordSet rsOsComm 	= JDTORecordFactory.getInstance().createRecordSet("OS");
				JDTORecord recOsComm 	= JDTORecordFactory.getInstance().create();
				
				recPara = JDTORecordFactory.getInstance().create();
				
				recPara.setField("CUST_CD"			, szCUST_CD);
				recPara.setField("DETAIL_ARR_CD"	, szDETAIL_ARR_CD);
				
				sQueryId = "com.inisteel.cim.yd.common.dao.ptOsCommDao.getNotPilingCdDetailList_01";
				intRtnVal = commDao.select(recPara, rsOsComm, sQueryId);	
				
				if (intRtnVal <= 0) {
					szMsg = " 고객사 / 상세착지별 주문정보를 찾을수 없습니다.";
					ydUtils.putLog(szMethodName, szMethodName, szMsg, YdConstant.ERROR);
					outRecord.setField("RTN_CD" 		, "0");	
					outRecord.setField("RTN_MSG" 		, szMsg);
					
					return outRecord;
				}
				
				for(int i = 1; i <= rsOsComm.size(); i++ ) {
					
					recOsComm = JDTORecordFactory.getInstance().create();
				
					rsOsComm.absolute(i);
					recOsComm = rsOsComm.getRecord();
					
					sORD_NO 			= recOsComm.getFieldString("ORD_NO");
					sORD_DTL 			= recOsComm.getFieldString("ORD_DTL");
					sORD_CONV_W 		= recOsComm.getFieldString("ORD_CONV_W");
					sORD_CONV_LEN 		= recOsComm.getFieldString("ORD_CONV_LEN");
					sORD_EA 			= recOsComm.getFieldString("ORD_EA"); 
					sORD_CONV_T	  		= recOsComm.getFieldString("ORD_CONV_T"); 
					
					PlateGdsYdUtil.procPtOsCommUpdateByOrder(   sORD_EA,
																sORD_CONV_T,
																sORD_CONV_W,
																sORD_CONV_LEN,
																("Y".equals(szREPR)? szCUST_CD:""),
																szYD_STRCHAR_GRP,
																sORD_NO,
																sORD_DTL); 
				}	
			}

			outRecord.setField("RTN_CD" 		, "1");	
			outRecord.setField("RTN_MSG" 		, "정상적으로 처리되었습니다.");
		
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally{
		}		
		return outRecord;
	}	// end of updPlateYdStrChar
	
