	/**
	 * 후판제품창고 선별 완료 전송 처리 
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 */
	public void procPlateYdShipMtCptSend(JDTORecord [] inDto) {
		int       intRtnVal    = 0;
		int       intSh        = 0;
		String    szMsg        = null;
		String    szMethodName = null;
		String	  szOperationName	= "후판제품선별완료전송";
		String    szYdSaveLoc  = null;
		String    szYD_STK_COL_GP = null;
		String    szYD_STK_BED_NO = null;
		String    szYD_STK_BED_WHIO_STAT = null;
		
		//Delegate
		YdDelegate ydDelegate           = new YdDelegate();
		JDTORecord    recPara  	= JDTORecordFactory.getInstance().create();
		JDTORecord    recTemp  	= JDTORecordFactory.getInstance().create();
		JDTORecord    recSndTemp=  JDTORecordFactory.getInstance().create();
		YdStockDao ydStockDao = new YdStockDao();
		YdStkBedDao ydStkBedDao = new YdStkBedDao();
		
		szMsg        = "";
		szMethodName = "procPlateYdShipMtCptSend";
		
		String szSTL_NO		= null;
		
		String sPreYdLoc	= "";
		
		try {
			szMsg = "[Jsp Session : "+szOperationName+"] 메소드 시작 - 대상재 건수["+inDto.length+"]";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
//			EAIHttpSender eaiHttpSender =null;				
//			eaiHttpSender =new EAIHttpSender();
//			eaiHttpSender.initService(EAIHttpSender.issnd);
			
			//TC CCODE
			recTemp.setField("JMS_TC_CD",		"YDDMR006");
			//SORTING_CONFIRM
			recTemp.setField("SORTING_CONFIRM",	"S");
			
				//저장위치 좌표설정화면 BED 수정
			for(int x=0;x<inDto.length;x++){
				szSTL_NO = yddatautil.setDataDefault(inDto[x].getFieldString("STL_NO"),     "").trim();
				
				szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신)[NB]로 수정 시작 ";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
	
				recPara.setField("STL_NO",     			szSTL_NO);
				recPara.setField("YD_AIM_RT_GP",    	YdConstant.AR_TRN_WO_WAIT_PLATE_SEL_CMPL_SND);
				recPara.setField("YD_RCPT_PLN_STR_LOC", yddatautil.setDataDefault(inDto[x].getField("YD_RCPT_PLN_STR_LOC"),     ""));
				//수정
				recPara.setField("MODIFIER",   			 yddatautil.setDataDefault(inDto[x].getFieldString("YD_USER_ID"),""));
				
		        intRtnVal = ydStockDao.updYdStock(recPara,0);
		        
				if (intRtnVal < 0) {
					szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신)[NB]로 수정 시 오류발생 : 루프 계속처리 - 반환값 : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					continue;
				}else if( intRtnVal == 0 ) {
					szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신)[NB]로 수정 시 존재하지 않습니다. - 루프계속처리";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					continue;
				}
		
				szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신)[NB]로 수정 완료 ";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신) 송신 시작 ";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				//STL_NO
				recTemp.setField("STL_NO", 			szSTL_NO);
				ydUtils.displayRecord(szOperationName, recTemp);
				
				//PIDEV:후판 선별 없음			
//				String sApplyYnPI = ydPICommDAO.ApplyYnPI("", szOperationName, "APPPI0", "*", "*");
//				if("N".equals(sApplyYnPI)) {
//					//Delegate 연결
//					ydDelegate.sendMsg(recTemp);
//				}
				
				//---------------------------------------------------------------------------
				// 선별완료 전송 BED는 완산으로 처리
				szYdSaveLoc = yddatautil.setDataDefault(inDto[x].getFieldString("YD_SAVE_LOC"),     "").trim();
				
				if (!"".equals(szYdSaveLoc)) {
					
					if(szYdSaveLoc.length() < 8) continue;
					
					/*
					 * 이미 변경된 저장위치 정보는 변경하지 않는다.
					 */
					if(!sPreYdLoc.equals(szYdSaveLoc.substring(0,8))){
						
						sPreYdLoc		= szYdSaveLoc.substring(0,8);
						
						szYD_STK_COL_GP = szYdSaveLoc.substring(0, 6);
						szYD_STK_BED_NO = szYdSaveLoc.substring(6, 8);
						szYD_STK_BED_WHIO_STAT = YdConstant.YD_STK_BED_WHIO_FULL;
						
						recPara.setField("YD_STK_COL_GP",     			szYD_STK_COL_GP);
						recPara.setField("YD_STK_BED_NO",     			szYD_STK_BED_NO);
						recPara.setField("YD_STK_BED_WHIO_STAT",     	szYD_STK_BED_WHIO_STAT);
						
						intRtnVal = ydStkBedDao.updYdStkbed(recPara, 0);
						
						if (intRtnVal < 0) {
							szMsg = "[Jsp Session : "+szOperationName+"] 적치열구분["+szYD_STK_COL_GP+"] 적치BED번호[" + szYD_STK_BED_NO + "]를 완산BED[F]로 수정 시 오류발생 : 루프 계속처리 - 반환값 : " + intRtnVal;
							ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
							continue;
						}else if( intRtnVal == 0 ) {
							szMsg = "[Jsp Session : "+szOperationName+"]  적치열구분["+szYD_STK_COL_GP+"] 적치BED번호[" + szYD_STK_BED_NO + "]를 완산BED[F]로 수정 시 존재하지 않습니다. - 루프계속처리";
							ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
							continue;
						}
						
						szMsg = "[Jsp Session : "+szOperationName+"] 적치열구분["+szYD_STK_COL_GP+"] 적치BED번호[" + szYD_STK_BED_NO + "]를 완산BED[F]로 수정 완료 ";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
						
						//L2 로 적치열 수정된 정보를 내려보내준다.
						recSndTemp =  JDTORecordFactory.getInstance().create();
						//recSndTemp.setField("MSG_ID", 			"YDY4L001");
						if(YdConstant.YD_GP_PLATE2_GDS_YARD.equals(YdCommonUtils.getPlateYdGpForL2(szYD_STK_COL_GP))) { //- 2012.12.21 추가 (3기)
							//2후판일 경우 MSG_ID 를 YDY8L001 로 설정한다. 
							recSndTemp.setField("MSG_ID", "YDY8L001");
							// 전사물류개선 2021. 4. 3
							if(PlateGdsYdUtil.isSendToEaiY9_ydStkColGp(szYD_STK_COL_GP)){
								recSndTemp.setField("MSG_ID", "YDY9L001");
							}
							
						} else {
							//1후판일 경우 MSG_ID 를 YDY4L001 로 설정한다.
							recSndTemp.setField("MSG_ID", "YDY4L001");
						}
						recSndTemp.setField("YD_INFO_SYNC_CD",  "4");
						//recSndTemp.setField("YD_GP", 			YdConstant.YD_GP_PLATE_GDS_YARD);
						recSndTemp.setField("YD_GP", 			szYD_STK_COL_GP.substring(0,1)); //- 2012.12.21 수정 (3기)
						recSndTemp.setField("YD_STK_COL_GP", 	szYD_STK_COL_GP);
						recSndTemp.setField("YD_STK_BED_NO", 	szYD_STK_BED_NO);
				
						
						szMsg = "[Jsp-Session "+szSessionName+" ] L2 로 적치열 수정된 정보 송신 시작" ;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
						
						ydDelegate.sendMsg(recSndTemp);
						
						szMsg = "[Jsp-Session "+szSessionName+" ] L2 로 적치열 수정된 정보 송신 완료" ;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					}
				}
				
	
				szMsg = "[Jsp Session : "+szOperationName+"] 재료["+szSTL_NO+"]를 운송지시대기(PLATE선별완료송신) 송신 완료 ";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				//**************************************************************************
				//**************************************************************************
			}
			
			szMsg = "[Jsp Session : "+szOperationName+"] 메소드끝";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		} catch (Exception e) {
			szMsg = "[Jsp Session : "+szOperationName+"] 예외발생 : " + e.getMessage();
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
	}	// end of procPlateYdShipMtCptSend
	
