	public void procPlateYdPilingCompletion(JDTORecord [] inDto) {
		int       intRtnVal    = 0;
		int       intSh        = 0;
		String    szMsg        = null;
		String    szMethodName = null;
		
		//Delegate
		JDTORecord    recPara  = JDTORecordFactory.getInstance().create();	
		
		szMsg        = "";
		szMethodName = "procPlateYdPilingCompletion";
		String szOperationName = "Piling 완료 처리";
			
		try {
			szMsg = "[SESSION] 후판제품창고 Piling 완료 처리 [ " + szMethodName + " ] \n";
			szMsg += "[R/T 모니터링] Piling 완료 처리 - 첫번째 재료 번호[ " + inDto[inDto.length - 1].getFieldString("STL_NO") + " ], "
				  +  "재료 매수 [ " + inDto.length + " ], "
			      +  "PILING CODE [ " + inDto[0].getFieldString("YD_BOOK_OUT_LOC") + " ] \n";
			ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
			
			// Pre Piler 실적 TL3CPP(P2YDL001) 29043
			//
			//후판작업자사번			PL_WRKER_EMPNO			VARCHAR2	10
			//후판작업근조				PL_WD					VARCHAR2	2
			//후판제품Piling작업일		PL_GDS_PILNG_WRK_DD		VARCHAR2	8
			//후판제품Piling단위번호	PL_GDS_PILNG_UNIT_NO	NUMBER		4
			//후판제품Piling매수		PL_GDS_PILNG_SH			NUMBER		2
			//후판L2제품번호1			PL_L2_TRK_NO1			VARCHAR2	16
			//후판Plate번호1			PL_PLATE_NO1			VARCHAR2	10
			//후판L2제품번호2			PL_L2_TRK_NO2			VARCHAR2	16
			//후판Plate번호2			PL_PLATE_NO2			VARCHAR2	10
			//후판L2제품번호3			PL_L2_TRK_NO3			VARCHAR2	16
			//후판Plate번호3			PL_PLATE_NO3			VARCHAR2	10
			//후판L2제품번호4			PL_L2_TRK_NO4			VARCHAR2	16
			//후판Plate번호4			PL_PLATE_NO4			VARCHAR2	10
			//후판L2제품번호5			PL_L2_TRK_NO5			VARCHAR2	16
			//후판Plate번호5			PL_PLATE_NO5			VARCHAR2	10
			
			
			// Y8YDL010 입고존 재료정보
			// RCPT_ZONE_GP			입고존 구분		VARCHAR2(1)		2후판 R/T 구분 (A,B,C)
			// ARR_LEV_GP			도착,출발구분		VARCHAR2(1)		도착(A), 출발(L)
			// MTL_SH				재료매수			VARCHAR2(2)		01~06
			// STL_NO1				1단_재료번호		VARCHAR2(11)	최하단 재료번호
			// STL_NO2				2단_재료번호		VARCHAR2(11)	2단 재료번호
			// STL_NO3				3단_재료번호		VARCHAR2(11)	3단 재료번호
			// STL_NO4				4단_재료번호		VARCHAR2(11)	4단 재료번호
			// STL_NO5				5단_재료번호		VARCHAR2(11)	5단 재료번호
			// STL_NO6				6단_재료번호		VARCHAR2(11)	6단 재료번호
			
			
			//--2013.03.05 추가 (3기)
			String szYD_STK_COL_GP = inDto[0].getFieldString("YD_STK_COL_GP");
			ydUtils.putLog(szSessionName, szMethodName , ">>>>>>>>>>>>>>>>>>>>>> YD_STK_COL_GP : " + szYD_STK_COL_GP , YdConstant.DEBUG);
			
			EJBConnector ejbConn = null;
			ejbConn = new EJBConnector("default", this);
			
			//if(szYD_STK_COL_GP.startsWith(YdConstant.YD_GP_PLATE2_GDS_YARD)) {
			if(szYD_STK_COL_GP.endsWith("RA")||szYD_STK_COL_GP.endsWith("RB")||szYD_STK_COL_GP.endsWith("RC")) {
				//2후판용 입고존 재료정보 --> 가상베드에 등록하는 것은 낱장도 처리하기 위해서 L2전문 Y8YDL010 으로 하기로 함
				
				//TC CCODE
				recPara.setField("MSG_ID",			"Y8YDL010");		
				recPara.setField("RCPT_ZONE_GP",	szYD_STK_COL_GP.substring(5,6));		
				recPara.setField("ARR_LEV_GP",		"L");		
				recPara.setField("MTL_SH",			"" + inDto.length);	
				for(int Loopi=0; Loopi<inDto.length; Loopi++){
					//재료번호
					recPara.setField("STL_NO"+(Loopi+1), inDto[inDto.length-(Loopi+1)].getFieldString("STL_NO"));
				}				
				
				ydUtils.displayRecord(szOperationName, recPara);
				
				//호출
				ejbConn.trx("RcptWrkDmdSeEJB", "procY8RcptZoneMtlInfo", recPara);
				
				
			} else {
				//1후판용 파일링 실적 호출
				
				//TC CCODE
				recPara.setField("JMS_TC_CD",			"P2YDL001");
				
				//전달할 전문 편집
				for(int Loopi=0; Loopi<inDto.length; Loopi++){
					//재료번호
					recPara.setField("PL_PLATE_NO"+(Loopi+1), inDto[inDto.length-(Loopi+1)].getFieldString("STL_NO"));
				}
				recPara.setField("PL_GDS_PILNG_SH",			"" + inDto.length);
			
				ydUtils.displayRecord(szOperationName, recPara);
				
				//호출
				ejbConn.trx("RcptWrkDmdSeEJB", "procP2PillingWr", recPara);
			}
			
			szMsg = "[SESSION] 후판제품창고 Piling 완료 처리 메소드 끝";
			ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
			
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
	}	// end of procPlateYdPilingCompletion
	
