				szMsg = "[Jsp Session : " + szOperationName + "] [" + i + "]번 재료번호[" + szSTL_NO + "]를 후판제품공통테이블의 현저장위치를 입고전 위치정보["+szYD_STK_COL_GP+"]로 수정 완료";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				
