			//	해당 베드를 먼저 조회해서 재료가 적치중인 지 판단.
			//--------------------------------------------------------------------------------------------------
			
			rsResult			= JDTORecordFactory.getInstance().createRecordSet("");
			recPara				= JDTORecordFactory.getInstance().create();
			
			recPara.setField("YD_STK_COL_GP", 		szYD_STK_COL_GP);
			recPara.setField("YD_STK_BED_NO", 		szYD_STK_BED_NO);
			
			//상단재료에서 하단재료순으로 조회
			szRtnMsg		= DaoManager.getYdStklyr(recPara, rsResult, 6);
			
			if( !szRtnMsg.equals(YdConstant.RETN_CD_SUCCESS) ) {
				
				szMsg = "[Jsp Session : "+ szOperationName +"] 해당베드[적치열:"+szYD_STK_COL_GP+", 적치베드:"+szYD_STK_BED_NO+"]에 적치중인 재료들 조회 시 오류발생 - 메세지 : " + szRtnMsg;
				ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.ERROR);
				
				return szRtnMsg;
			}
			
			rsResult.first();
			
			recPara			= rsResult.getRecord();
			
			//최상단의 재료만 추출
			szSTL_NO						= ydDaoUtils.paraRecChkNull(recPara, "STL_NO");
			szYD_STK_LYR_MTL_STAT			= ydDaoUtils.paraRecChkNull(recPara, "YD_STK_LYR_MTL_STAT");
			
			//--------------------------------------------------------------------------------------------------
			
			
			//--------------------------------------------------------------------------------------------------
			//	크레인스케줄이 존재하는 지 판단
			//--------------------------------------------------------------------------------------------------
			
			//if( szYD_STK_LYR_MTL_STAT.equals(YdConstant.YD_STK_LYR_MTL_STAT_UN_WAIT))	{
			//	//권상대기이면 크레인스케줄이 존재하는 것으로 판단 처리
			//	szMsg = "[Jsp Session : "+ szOperationName +"] 해당베드[적치열:"+szYD_STK_COL_GP+", 적치베드:"+szYD_STK_BED_NO+"]에 적치중인 재료가 크레인스케줄에 등록되어 있으므로 Book-Out취소 불가";
