			//szMsg = "[Jsp Session : "+ szOperationName +"] 해당베드[적치열:"+szYD_STK_COL_GP+", 적치베드:"+szYD_STK_BED_NO+"]에 적치중인 재료가 크레인스케줄에 등록되어 있지 않으므로 Book-Out취소 가능합니다.";
			//ydUtils.putLog(szSessionName, szMethodName , szMsg , YdConstant.DEBUG);
			
