			recPara.setField("YD_MTL_W_GP",			yddatautil.setDataDefault(inDto.getField("YD_PILING_CD"),	"").substring(4,6));
			recPara.setField("YD_MTL_L_GP",			szYD_MTL_L_GP);
			
