	/**
	 * 후판제품 야드 이송재료LIST
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecordSet getYdFrtoMoveMtlList(JDTORecord inDto) throws DAOException {
		/*
		 * 통합 슬라브 야드의 이송재료 LIST QUERY 에서 슬라브공통과 주편공통을 후판 공통 테이블로 변경하여 조인
		 */
		
		//JDTO변수 정의
		JDTORecord       recPara        = null;
		JDTORecordSet    outRecSet      = null;
		//DAO 변수 정의
		YdStockDao  ydStockDao  		= new YdStockDao();
		//기본변수 정의
		String      szMsg        		= "";
		String      szMethodName		= "getYdFrtoMoveMtlList";
		String		szOperationName		= "후판제품 이송재료LIST";
		//로컬변수 정의
	    String      szYD_AIM_YD_GP		= null;
	    String      szYD_AIM_BAY_GP 	= null;
	    String 		szSPOS_WLOC_CD		= null;
		String		szARR_WLOC_CD		= null;
		String		szDATE_FROM			= null;
		String 		szDATE_TO			= null;
		String		szWO_STATE			= null;
		String		szIN_OUT_GP			= null;
		String		szYD_GP				= null;
		String		szYD_DONG_GP		= null;
		String		szYD_SPAN_GP		= null;
		String		szYD_COL_GP			= null;
		String		szYD_STK_COL_GP		= null;
		String		szYD_AIM_RT_GP		= null;
		
		int intRtnVal = 0;
		
		try {
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 : 파라미터 확인 ";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			
			ydUtils.displayRecord(szOperationName, inDto);
			
			szIN_OUT_GP	 = ydDaoUtils.paraRecChkNull(inDto, "IN_OUT_GP");			//입고/출고구분
			szYD_DONG_GP = ydDaoUtils.paraRecChkNull(inDto, "YD_DONG_GP");
			szYD_SPAN_GP = ydDaoUtils.paraRecChkNull(inDto, "YD_SPAN_GP");
			szYD_COL_GP  = ydDaoUtils.paraRecChkNull(inDto, "YD_COL_GP");
			
			if( szIN_OUT_GP.equals("1")) {					//입고
				szARR_WLOC_CD	= ydDaoUtils.paraRecChkNull(inDto, "SPOS_WLOC_CD");	
				szSPOS_WLOC_CD	= ydDaoUtils.paraRecChkNull(inDto, "ARR_WLOC_CD");
				szYD_STK_COL_GP = "";
			}else{											//출고
				szSPOS_WLOC_CD	= ydDaoUtils.paraRecChkNull(inDto, "SPOS_WLOC_CD");
				szARR_WLOC_CD	= ydDaoUtils.paraRecChkNull(inDto, "ARR_WLOC_CD");
				szYD_STK_COL_GP = szYD_DONG_GP + szYD_SPAN_GP + szYD_COL_GP;
			}
			
			szDATE_FROM		= ydDaoUtils.paraRecChkNull(inDto, "DATE_FROM");
			szDATE_TO		= ydDaoUtils.paraRecChkNull(inDto, "DATE_TO");
			szWO_STATE		= ydDaoUtils.paraRecChkNull(inDto, "WO_STATE");
			szYD_AIM_RT_GP	= ydDaoUtils.paraRecChkNull(inDto, "YD_AIM_RT_GP");
			szYD_AIM_YD_GP	= ydDaoUtils.paraRecChkNull(inDto, "YD_AIM_YD_GP");
			szYD_AIM_BAY_GP = ydDaoUtils.paraRecChkNull(inDto, "YD_AIM_BAY_GP");
			szYD_GP			= ydDaoUtils.paraRecChkNull(inDto, "YD_GP");
			
			outRecSet      = JDTORecordFactory.getInstance().createRecordSet("YD");
			recPara        = JDTORecordFactory.getInstance().create();
			
		    recPara.setField("WO_STATE",     	szWO_STATE);
		    recPara.setField("SPOS_WLOC_CD", 	szSPOS_WLOC_CD);
		    recPara.setField("ARR_WLOC_CD",  	szARR_WLOC_CD);
		    recPara.setField("YD_GP",  			szYD_GP);
		    recPara.setField("DATE_FROM",    	szDATE_FROM);
		    recPara.setField("DATE_TO",      	szDATE_TO);
		    recPara.setField("YD_STK_COL_GP",    szYD_STK_COL_GP);
		    recPara.setField("YD_AIM_RT_GP",    szYD_AIM_RT_GP);
		    recPara.setField("YD_AIM_YD_GP",    szYD_AIM_YD_GP);
		    recPara.setField("YD_AIM_BAY_GP",   szYD_AIM_BAY_GP);
			recPara.setField("PAGE_NO",      	inDto.getField("PAGE_NO"));		
			recPara.setField("ROW_CNT",      	inDto.getField("ROWCOUNT"));
			
			if( szWO_STATE.equals("1")) {			//지시
				intRtnVal = ydStockDao.getYdStock(recPara, outRecSet, 155);
			}else{									//완료
				intRtnVal = ydStockDao.getYdStock(recPara, outRecSet, 156);
			}
			
			if (intRtnVal < 0) {
				if (intRtnVal == -1) {
					szMsg = "[JSP Session : "+szOperationName+"] 오류발생[1] - 반환값 : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				} else {
					szMsg = "[JSP Session : "+szOperationName+"] 파라미터 오류 - 반환값 : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}
				//return outRecSet;
				return outRecSet;
			} // end of if
			
			szMsg = "[JSP Session : "+szOperationName+"] 조회 성공 : 대상재건수[" + intRtnVal + "]";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return outRecSet;
	}//end of getYdFrtoMoveMtlList

	/**
	 * 후판제품 야드 이송재료LIST 목표행선 / 목표야드 / 목표동 수정
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String updPlateYdFrToMoveMtlList(JDTORecord [] inDto) throws DAOException {
		/*
		 * 통합 슬라브 야드의 이송재료 LIST의 목표행선/목표야드/목표동 수정 기능과 같은 기능으로 슬라브 공통 수정처리 기능과 동일
		 */
		int intRtnVal 		= 0;
		String szMsg		= "";
		String szMethodName	= "updPlateYdFrToMoveMtlList";
		String szRcvMsg 	= "";
		
		JDTORecord recPara = JDTORecordFactory.getInstance().create();		
		YdStockDao ydStockDao = new YdStockDao();
		 
		try {
			//메뉴 페이지 목록을 수정한다.
			for(int x=0;x<inDto.length;x++){
				szMsg = "[JSP Session] 후판제품 야드 이송재료 LIST 목표행선 / 목표야드 / 목표동 수정 - 재료 번호 [ " + yddatautil.setDataDefault(inDto[x].getField("STL_NO"), "") + " ]\n";
		        ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		        
				//수정할 항목 SETTING
				recPara = JDTORecordFactory.getInstance().create();
				// 재료번호
				recPara.setField("STL_NO",			yddatautil.setDataDefault(inDto[x].getField("STL_NO"),			""));
				// 야드 목표 행선 구분
				recPara.setField("YD_AIM_RT_GP",	yddatautil.setDataDefault(inDto[x].getField("YD_AIM_RT_GP"),	"").toUpperCase());
				// 야드 목표 야드 구분				
				recPara.setField("YD_AIM_YD_GP",	yddatautil.setDataDefault(inDto[x].getField("YD_AIM_YD_GP"),	"").toUpperCase());
				// 야드 목표 동 구분				
				recPara.setField("YD_AIM_BAY_GP",	yddatautil.setDataDefault(inDto[x].getField("YD_AIM_BAY_GP"),	"").toUpperCase());	
				intRtnVal = ydStockDao.updYdStock(recPara, 0);
				
	        	szMsg += "[JSP Session] 이송재료 LIST 목표행선 / 목표야드 / 목표동 수정 - 해당 재료 [" + yddatautil.setDataDefault(inDto[x].getFieldString("STL_NO"), "") + "] 의  "
	        		  + "야드 목표 행선 구분 [" + yddatautil.setDataDefault(inDto[x].getField("YD_AIM_RT_GP"), "") + "], 야드 목표 야드 구분 ["+ yddatautil.setDataDefault(inDto[x].getField("YD_AIM_YD_GP"), "")+ "], "
	        		  + "야드 목표 동 구분 [" + yddatautil.setDataDefault(inDto[x].getField("YD_AIM_BAY_GP"), "") + "]이 성공적으로 수정되었습니다!";
	        	ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
	        	
				if (intRtnVal < 0) {
					if (intRtnVal == -1) {
						szMsg = "routine error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "parameter error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}
					szRcvMsg = "수정시DAO ERROR 발생";
					return  szRcvMsg;
					
				} // end of if
				
			}
			return YdConstant.RETN_CD_SUCCESS;
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally{
		}		
	}	// end of updPlateYdFrToMoveMtlList
	
	
	public String chkPlateYdBedWLGp(String szYdStkColGp, String szYdStkBedNo, String szYdToLocGuide ) throws DAOException {
		
		String      szMethodName		= "chkPlateYdBedWLGp";
		String		szOperationName		= "FROM배드_TO배드 -폭길이구분 Check";
		String      szMsg = "";
		String      szFR_BED_W_GP = null;
		String      szFR_BED_L_GP = null;
		String      szTO_BED_W_GP = null;
		String      szTO_BED_L_GP = null;
		String      szFR_COL_W_GP = null;
		String      szTO_COL_W_GP = null;
		String      szTO_BED_ACT_STAT = null;
		String      szTO_BED_WHIO_STAT = null;
		
		int         intRtnVal;
		
		String szRtnMsg = YdConstant.RETN_CD_SUCCESS;
		YdStkBedDao ydStkBedDao = new YdStkBedDao();
		
		JDTORecord recPara = JDTORecordFactory.getInstance().create();
		JDTORecordSet 	outRecSet 	= JDTORecordFactory.getInstance().createRecordSet("retTmp");
		
		try {
			
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 ";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			
			recPara.setField("YD_STK_COL_GP1",	szYdStkColGp);
			recPara.setField("YD_STK_BED_NO1",	szYdStkBedNo);
			recPara.setField("YD_STK_COL_GP2",	szYdToLocGuide.substring(0, 6));
			recPara.setField("YD_STK_BED_NO2",	szYdToLocGuide.substring(6, 8));
			
			
			intRtnVal = ydStkBedDao.getYdStkbed(recPara, outRecSet, 29);
			
			if (intRtnVal <= 0) {
				szMsg = "[JSP Session : "+szOperationName+"] FROM_BED["+szYdStkColGp+szYdStkBedNo+"]  FROM_BED["+szYdToLocGuide+"]조회 시 오류발생[1] - 반환값 : " + intRtnVal;
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				szRtnMsg = szMsg;
				return szRtnMsg;
			}
			
			outRecSet.absolute(1);
			JDTORecord recResult = outRecSet.getRecord();
			
			szFR_BED_W_GP = ydDaoUtils.paraRecChkNull(recResult, "FR_BED_W_GP");
			szFR_BED_L_GP = ydDaoUtils.paraRecChkNull(recResult, "FR_BED_L_GP");
			szTO_BED_W_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_W_GP");
			szTO_BED_L_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_L_GP");
			
			szFR_COL_W_GP = ydDaoUtils.paraRecChkNull(recResult, "FR_COL_W_GP");
			szTO_COL_W_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_COL_W_GP");
			szTO_BED_ACT_STAT = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_ACT_STAT");
			szTO_BED_WHIO_STAT = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_WHIO_STAT");
			
			
			//적치배드 활성상태 체크
			if(szTO_BED_ACT_STAT.equals("C")) {
				szRtnMsg = "TO_BED가 비활성화 상태입니다";
				return szRtnMsg;
			}
			
			if(szTO_BED_ACT_STAT.equals("N")) {
				szRtnMsg = "TO_BED가 사용 불가 상태입니다";
				return szRtnMsg;
			}
			
			// 적치배드 입출고상태 체크
			if(szTO_BED_WHIO_STAT.equals("F")) {
				szRtnMsg = "TO_BED가 완산BED 입니다";
				return szRtnMsg;
			}
			
			if(szTO_BED_WHIO_STAT.equals("X")) {
				szRtnMsg = "TO_BED가 입출고금지BED 입니다";
				return szRtnMsg;
			}
			
			
			//적치배드 폭구분 비교
			if (szFR_BED_W_GP.equals("M") && szTO_BED_W_GP.equals("S")) {
				szRtnMsg = "폭구분 오류 FROM_BED[M],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_BED_W_GP.equals("L") && szTO_BED_W_GP.equals("S")) {
				szRtnMsg = "폭구분 오류 FROM_BED[L],TO_BED[S]";
				return szRtnMsg;
						
			}else if (szFR_BED_W_GP.equals("L") && szTO_BED_W_GP.equals("M")) {
				szRtnMsg = "폭구분 오류 FROM_BED[L],TO_BED[M]";
				return szRtnMsg;
			}

//DONG_INSERT			
			//적치배드 길이구분 비교
			if (szFR_BED_L_GP.equals("M") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_BED[M],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_BED_L_GP.equals("L") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_BED[L],TO_BED[S]";
				return szRtnMsg;
						
			}else if (szFR_BED_L_GP.equals("L") && szTO_BED_L_GP.equals("M")) {
				szRtnMsg = "길이구분 오류 FROM_BED[L],TO_BED[M]";
				return szRtnMsg;
				
			}else if (szFR_BED_L_GP.equals("X") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_BED[X],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_BED_L_GP.equals("X") && szTO_BED_L_GP.equals("M")) {
				szRtnMsg = "길이구분 오류 FROM_BED[X],TO_BED[M]";
				return szRtnMsg;
				
			}else if (szFR_BED_L_GP.equals("X") && szTO_BED_L_GP.equals("L")) {
				szRtnMsg = "길이구분 오류 FROM_BED[X],TO_BED[L]";
				return szRtnMsg;
				
			}
			
			
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		}
		return szRtnMsg;
	} // end of chkPlateYdBedWLGp
	
public String chkPlateYdStlBedWLGp(String szStl_No, String szYdToLocGuide ) throws DAOException {
		
		String      szMethodName		= "chkPlateYdStlBedWLGp";
		String		szOperationName		= "FROM재료_TO배드 -폭길이구분 Check";
		String      szMsg = "";
		String      szFR_STL_W_GP = null;
		String      szFR_STL_L_GP = null;
		String      szTO_BED_W_GP = null;
		String      szTO_BED_L_GP = null;
		String      szFR_COL_W_GP = null;
		String      szTO_COL_W_GP = null;
		String      szTO_BED_ACT_STAT = null;
		String      szTO_BED_WHIO_STAT = null;
		String      szYD_PILING_CD = null;
		
		int         intRtnVal;
		int         intSpn =0;		
		
		String szRtnMsg = YdConstant.RETN_CD_SUCCESS;
		YdStkBedDao ydStkBedDao = new YdStkBedDao();
		
		JDTORecord recPara = JDTORecordFactory.getInstance().create();
		JDTORecordSet 	outRecSet 	= JDTORecordFactory.getInstance().createRecordSet("retTmp");
		
		try {
			
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 ";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			
			recPara.setField("STL_NO",	szStl_No);
			recPara.setField("YD_STK_COL_GP",	szYdToLocGuide.substring(0, 6));
			recPara.setField("YD_STK_BED_NO",	szYdToLocGuide.substring(6, 8));
			
			
			intRtnVal = ydStkBedDao.getYdStkbed(recPara, outRecSet, 35);
			
			if (intRtnVal <= 0) {
				szMsg = "[JSP Session : "+szOperationName+"] FROM_STL["+szStl_No+"]  FROM_BED["+szYdToLocGuide+"]조회 시 오류발생[1] - 반환값 : " + intRtnVal;
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				szRtnMsg = szMsg;
				return szRtnMsg;
			}
			
			outRecSet.absolute(1);
			JDTORecord recResult = outRecSet.getRecord();
			
			szFR_STL_W_GP = ydDaoUtils.paraRecChkNull(recResult, "YD_MTL_W_GP").substring(0,1);
			szFR_STL_L_GP = ydDaoUtils.paraRecChkNull(recResult, "YD_MTL_L_GP").substring(0,1);
			szTO_BED_W_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_W_GP");
			szTO_BED_L_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_L_GP");
			
			szYD_PILING_CD = ydDaoUtils.paraRecChkNull(recResult, "YD_PILING_CD");
			
			szTO_COL_W_GP = ydDaoUtils.paraRecChkNull(recResult, "TO_COL_W_GP");
			szTO_BED_ACT_STAT = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_ACT_STAT");
			szTO_BED_WHIO_STAT = ydDaoUtils.paraRecChkNull(recResult, "TO_BED_WHIO_STAT");
			//boolean isNumeric = szYdToLocGuide.substring(2,4).chars().allMatch(Character::isDigit); 
			boolean isNumeric =  szYdToLocGuide.substring(2,4).matches("[+-]?\\d*(\\.\\d+)?");
			
			if (isNumeric) {
				intSpn   = Integer.parseInt(szYdToLocGuide.substring(2, 4));
			}
						
			
			
			//적치배드 활성상태 체크
			if(szTO_BED_ACT_STAT.equals("C")) {
				szRtnMsg = "TO_BED가 비활성화 상태입니다";
				return szRtnMsg;
			}
			
			if(szTO_BED_ACT_STAT.equals("N")) {
				szRtnMsg = "TO_BED가 사용 불가 상태입니다";
				return szRtnMsg;
			}
			
			// 적치배드 입출고상태 체크
			if(szTO_BED_WHIO_STAT.equals("F")) {
				szRtnMsg = "TO_BED가 완산BED 입니다";
				return szRtnMsg;
			}
			
			if(szTO_BED_WHIO_STAT.equals("X")) {
				szRtnMsg = "TO_BED가 입출고금지BED 입니다";
				return szRtnMsg;
			}
			
			if(!"".equals(szYD_PILING_CD)) {
				if(szYD_PILING_CD.startsWith("M")) {
					return szRtnMsg;
				}
			}
			
			//적치열 폭구분 비교

			
			
			//적치배드 폭구분 비교
			if (szFR_STL_W_GP.equals("M") && szTO_BED_W_GP.equals("S")) {
				szRtnMsg = "폭구분 오류 FROM_재료[M],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_STL_W_GP.equals("L") && szTO_BED_W_GP.equals("S")) {
				szRtnMsg = "폭구분 오류 FROM_재료[L],TO_BED[S]";
				return szRtnMsg;
						
			}else if (szFR_STL_W_GP.equals("L") && szTO_BED_W_GP.equals("M")) {
				szRtnMsg = "폭구분 오류 FROM_재료[L],TO_BED[M]";
				return szRtnMsg;
			}
			
			//적치배드 길이구분 비교
			if (szFR_STL_L_GP.equals("M") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_재료[M],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_STL_L_GP.equals("L") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_재료[L],TO_BED[S]";
				return szRtnMsg;
						
			}else if (szFR_STL_L_GP.equals("L") && szTO_BED_L_GP.equals("M")) {
				szRtnMsg = "길이구분 오류 FROM_재료[L],TO_BED[M]";
				return szRtnMsg;
			}else if (szFR_STL_L_GP.equals("X") && szTO_BED_L_GP.equals("S")) {
				szRtnMsg = "길이구분 오류 FROM_재료[X],TO_BED[S]";
				return szRtnMsg;
				
			}else if (szFR_STL_L_GP.equals("X") && szTO_BED_L_GP.equals("M")) {
				szRtnMsg = "길이구분 오류 FROM_재료[X],TO_BED[M]";
				return szRtnMsg;
				
			}else if (szFR_STL_L_GP.equals("X") && szTO_BED_L_GP.equals("L")) {
				szRtnMsg = "길이구분 오류 FROM_재료[X],TO_BED[L]";
				return szRtnMsg;
				
			}
			//AT000 2022.11.17 3. 긴급재 선별작업지 시 화면에서 제품 선별 시 TO위치를 지정하여 선별 개선 건
			if ( "TB".equals(szYdToLocGuide.substring(0, 2)) && intSpn > 03){  
				if (szFR_STL_L_GP.equals("L") && szTO_BED_L_GP.equals("X")) {
					szRtnMsg = "길이구분 오류 FROM_재료[L],TO_BED[X]";
					return szRtnMsg;
				}
				
			}
			
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		}
		return szRtnMsg;
	} // end of chkPlateYdStlBedWLGp
	
	public String getUgSelToLoc(String szYdGp,String szYdBayGp,
								String szGate,String szCustCd,
								String szDetailArrCd,
								String szYdMtlWGp,String szYdMtlLGp) throws DAOException {
		
		String      szMethodName		= "getUgSelToLoc";
		String		szOperationName		= "선별 To위치베드 검색";
		String      szMsg = "";
		
		int         intRtnVal;
		
		String szRtnMsg = YdConstant.RETN_CD_SUCCESS;
		YmEtcDao dao = new YmEtcDao();
		
		JDTORecord recPara = JDTORecordFactory.getInstance().create();
		JDTORecordSet 	outRecSet 	= JDTORecordFactory.getInstance().createRecordSet("retTmp");
		
		try {
			
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 ";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			recPara.setField("YD_GP",			szYdGp);
			recPara.setField("YD_BAY_GP",		szYdBayGp);
			recPara.setField("GATE",			szGate);
			recPara.setField("CUST_CD",			szCustCd);
			recPara.setField("DETAIL_ARR_CD",	szDetailArrCd);
			recPara.setField("YD_MTL_W_GP",		szYdMtlWGp);
			recPara.setField("YD_MTL_L_GP",		szYdMtlLGp);
			
			intRtnVal = dao.getYmEtcDao(recPara, outRecSet, 6);
			
			if (intRtnVal <= 0) {
				return "XX010101";
			}
			
			outRecSet.absolute(1);
			JDTORecord recResult = outRecSet.getRecord();
			
			return ydDaoUtils.paraRecChkNull(recResult, "TO_LOC");
			
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		}
	} // end of chkPlateYdStlBedWLGp
	
	/**
	 * 이적대상재를 준비스케줄에 등록
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String insYdPrepSchByManual(JDTORecord[] inDto) throws DAOException {
		/*
		 * 업무기준 : 1. 그리드로 넘겨진 대상재들을 준비스케줄에 등록
		 * 				1-1. 준비스케줄 등록
		 * 				1-2. 준비재료 등록
		 * 				
		 * 수정자 : 임춘수
		 * 수정일 : 2009.09.28
		 * 비고 : 슬라브야드꺼를 후판야드로 가져옴 (석창화 , 2009.11.11)
		 * BED별 이적대상제 조회화면에서 준비스케줄 등록을 처리하기위해서 작업
		 */
		//JDTO변수 정의
		JDTORecord       recTemp        = null;
		//DAO 변수 정의
		YdPrepMtlDao	ydPrepMtlDao	= new YdPrepMtlDao();
		YdPrepSchDao	ydPrepSchDao	= new YdPrepSchDao();
		YdStkLyrDao     ydStkLyrDao     = new YdStkLyrDao();
		//기본변수 정의
		String      szMsg        		= "";
		String      szMethodName		= "insYdPrepSchByManual";
		String		szOperationName		= "BED별 이적대상제 -준비스케줄등록";
		String		szRtnMsg			= YdConstant.RETN_CD_SUCCESS;
		//로컬변수 정의
		String		szYD_AIM_YD_GP		= null;
	    String      szYD_AIM_BAY_GP 	= null;
	    //String		szARR_WLOC_CD		= null;
		int		intLOT_SH				= 0;
		String 		szYD_GP				= null;
		String		szYD_STK_COL_GP		= null;
		String		szYD_PREP_SCH_ID	= null;
		String		szUserId			= null;
		String		szYD_SCH_CD			= null;
		String		szSTL_NO			= null;
		String 		szYD_STK_BED_NO		= null;
		String		szYD_STK_LYR_NO 	= null;
		String      szYD_TO_LOC_GUIDE   = null;
		String      szYD_TO_LOC_DCSN_MTD = null;
		//String      szGRP_CNT           = null;
		int         intGRP_CNT         = 0;
		String      szSPAN_GP           = null;
		//long      lngGRP_WT            = 0;
		String      szSTL_LIST          = null;
		String      szJB_GP             = "";
		String      szJB_GP_old         = "";
		long		lngYD_MTL_WT		= 0;
		long		lngYD_MTL_WT_SUM	= 0;
		int intRtnVal = 0;
		
		
		JDTORecordSet 	outRecSet 	= JDTORecordFactory.getInstance().createRecordSet("retTmp");
		JDTORecord recData = JDTORecordFactory.getInstance().create();
		
		try {
			intLOT_SH = inDto.length;
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 - 대상건수["+intLOT_SH+"]";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			
			for (int row = 0; row < inDto.length; row++) {
				szJB_GP = ydDaoUtils.paraRecChkNull(inDto[row], "JB_GP");
				
				if(!szJB_GP_old.equals(szJB_GP)) {
					szUserId 		= ydDaoUtils.paraRecChkNull(inDto[row], "YD_USER_ID");
					szYD_TO_LOC_GUIDE = String.valueOf(ydDaoUtils.paraRecChkNull(inDto[row], "YD_TO_LOC_GUIDE").toUpperCase());
					
					if(!szYD_TO_LOC_GUIDE.equals("")){
						if(!"K".equals(szYD_TO_LOC_GUIDE.substring(0,1)) && szYD_TO_LOC_GUIDE.length() == 7) {
							szYD_TO_LOC_GUIDE = "K" + szYD_TO_LOC_GUIDE;
						}
					}
					
					//szARR_WLOC_CD 	= ydDaoUtils.paraRecChkNull(inDto[0], "ARR_WLOC_CD");
					szYD_STK_COL_GP = ydDaoUtils.paraRecChkNull(inDto[row], "YD_STK_COL_GP");
					szYD_STK_BED_NO = ydDaoUtils.paraRecChkNull(inDto[row], "YD_STK_BED_NO");
					
					intGRP_CNT = 0;
					//for(int k = 0; k < inDto.length; k++ ) {
					//	intGRP_CNT += ydDaoUtils.paraRecChkNullLong(inDto[k], "GRP_CNT");
					//}
					
					//lngGRP_WT = ydDaoUtils.paraRecChkNullLong(inDto[i], "GRP_WT");
					
					if (!szYD_TO_LOC_GUIDE.equals("")) {
						szRtnMsg = this.chkPlateYdBedWLGp(szYD_STK_COL_GP, szYD_STK_BED_NO, szYD_TO_LOC_GUIDE);
						
						if (szRtnMsg != YdConstant.RETN_CD_SUCCESS) {
							return szRtnMsg;
						}
						//szYD_AIM_BAY_GP = szYD_STK_COL_GP.substring(1,2);
						szYD_TO_LOC_DCSN_MTD = "F";
					}
					szYD_AIM_YD_GP = "K";
					
					szYD_GP = szYD_STK_COL_GP.substring(0, 1);
					
					szYD_SCH_CD = szYD_STK_COL_GP.substring(0, 2) + "YD";
					szSPAN_GP = szYD_STK_COL_GP.substring(2,4);
					
					if(szSPAN_GP.equals(YdConstant.SPAN_ORDER_NEW_04)|| 
					   szSPAN_GP.equals(YdConstant.SPAN_ORDER_NEW_05)||	
					   szSPAN_GP.equals(YdConstant.SPAN_ORDER_NEW_06)){
						szYD_SCH_CD = szYD_SCH_CD + "12MM";
					} else if(szSPAN_GP.equals(YdConstant.SPAN_ORDER_NEW_07)|| 
							  szSPAN_GP.equals(YdConstant.SPAN_ORDER_NEW_TP)){
						szYD_SCH_CD = szYD_SCH_CD + "34MM";
					}
					
					//준비스케줄 등록
					szYD_PREP_SCH_ID = ydPrepSchDao.getYdPrepschId();
					recTemp = JDTORecordFactory.getInstance().create();
					recTemp.setField("YD_PREP_SCH_ID", szYD_PREP_SCH_ID);
					recTemp.setField("YD_SCH_CD", szYD_SCH_CD);
					recTemp.setField("REGISTER", szUserId);
					recTemp.setField("YD_GP", szYD_GP);
					recTemp.setField("YD_PREP_WK_ST", "S");  //선별:S,  상차Lot:L
					
					recTemp.setField("YD_TO_LOC_GUIDE", szYD_TO_LOC_GUIDE);
					recTemp.setField("YD_TO_LOC_DCSN_MTD", szYD_TO_LOC_DCSN_MTD);
					recTemp.setField("YD_AIM_YD_GP",    szYD_AIM_YD_GP);
					recTemp.setField("YD_AIM_BAY_GP", szYD_AIM_BAY_GP);
					recTemp.setField("YD_CARASGN_SEQ", YdConstant.YD_CARASGN_SEQ_MAN_DEFAULT);
					
					//recTemp.setField("YD_INV_SUM_WT","" + lngGRP_WT);
					
					intRtnVal = ydPrepSchDao.insYdPrepsch(recTemp);
					
					if( intRtnVal < 0 ) {
						szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"] 등록 시 오류발생[1] - 반환값 : " + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}else if( intRtnVal == 0 ) {
						szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"] 등록 시 오류발생[2] - 반환값 : " + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}else{
						szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"] 등록 성공 ";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					}
					
					szJB_GP_old = szJB_GP;
					lngYD_MTL_WT_SUM = 0;
					
					for(int i = row; i < inDto.length; i++ ) {
						szJB_GP = ydDaoUtils.paraRecChkNull(inDto[i], "JB_GP");
						
						if (szJB_GP_old.equals(szJB_GP)) {
						
							szSTL_LIST = ydDaoUtils.paraRecChkNull(inDto[i], "STL_LIST");
							String[] szPrepMtl = szSTL_LIST.split(",");
							JDTORecord recPara = JDTORecordFactory.getInstance().create();
							
							intGRP_CNT += szPrepMtl.length;
							
							for(int j = 0; j < szPrepMtl.length; j++ ) {
								
								szSTL_NO  		= szPrepMtl[j];
								recPara.setField("STL_NO",szSTL_NO);
								
								outRecSet 	= JDTORecordFactory.getInstance().createRecordSet("retTmp");
								
								intRtnVal = ydStkLyrDao.getYdStklyr(recPara, outRecSet, 3);
								
								outRecSet.first();
								recData = outRecSet.getRecord();
													
								szYD_STK_COL_GP = ydDaoUtils.paraRecChkNull(recData, "YD_STK_COL_GP");
								szYD_STK_BED_NO = ydDaoUtils.paraRecChkNull(recData, "YD_STK_BED_NO");
								szYD_STK_LYR_NO = ydDaoUtils.paraRecChkNull(recData, "YD_STK_LYR_NO");
								
													
								//준비재료 등록
								recTemp = JDTORecordFactory.getInstance().create();
								recTemp.setField("STL_NO", szSTL_NO);
								recTemp.setField("YD_PREP_SCH_ID", szYD_PREP_SCH_ID);
								recTemp.setField("REGISTER", szUserId);
								recTemp.setField("YD_STK_COL_GP", szYD_STK_COL_GP);
								recTemp.setField("YD_STK_BED_NO", szYD_STK_BED_NO);
								recTemp.setField("YD_STK_LYR_NO", szYD_STK_LYR_NO);
								
								intRtnVal = ydPrepMtlDao.insYdPrepmtl(recTemp);
								
								if( intRtnVal < 0 ) {
									szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"]의 ["+(j + 1)+"]번재료["+szSTL_NO+"] 등록 시 오류발생[1] - 반환값 : " + intRtnVal;
									ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
								}else if( intRtnVal == 0 ) {
									szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"]의 ["+(j + 1)+"]번재료["+szSTL_NO+"] 등록 시 오류발생[2] - 반환값 : " + intRtnVal;
									ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
								}else{
									szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄["+szYD_PREP_SCH_ID+"]의 ["+(j + 1)+"]번재료["+szSTL_NO+"] 등록 성공 ";
									ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
								}
							}
							
							
						} else {
							row = i-1;
							break;
						}
						
						lngYD_MTL_WT	= ydDaoUtils.paraRecChkNullLong(inDto[i], "YD_MTL_WT");
						lngYD_MTL_WT_SUM += lngYD_MTL_WT;
						
					} //end of for(i)
					
					recTemp = JDTORecordFactory.getInstance().create();
					//준비스케줄수정
					recTemp.setField("YD_PREP_SCH_ID", szYD_PREP_SCH_ID);
					recTemp.setField("YD_INV_SUM_WT", "" + lngYD_MTL_WT_SUM);
					recTemp.setField("YD_EQP_WRK_SH", String.valueOf(intGRP_CNT));
					intRtnVal = ydPrepSchDao.updYdPrepsch(recTemp, 0);
				
				}
			} //end of for(row)
			szMsg = "[JSP Session : "+szOperationName+"] 준비스케줄 등록 성공 - 메소드 끝";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return szRtnMsg;
	}//end of insYdPrepSchByManual
	
	
