	/**
	 * 후판제품 PDA 입고제품검수화면 단정보 변경 
	 * 2009.11.30
	 * 권오창	
	 * 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public void updChgPlateYdStkLyrNo(JDTORecord [] inDto) throws DAOException {
		// DAO 및 UTIL객체 생성
		YdStkLyrDao ydStkLyrDao      = new YdStkLyrDao(); 
		YdStkColDao ydStkcolDao      = new YdStkColDao();
		YdStkBedDao ydStkBedDao      = new YdStkBedDao();
		YdDelegate ydDelegate        = new YdDelegate();
		YdDaoUtils ydDaoUtils        = new YdDaoUtils();
	
		
		// 레코드 선언
		JDTORecord recPara           = null;
		JDTORecord paraRec           = null;
		JDTORecord recGetVal         = null;
		JDTORecordSet outRecSet      = null;

		
		// 변수 선언
		String szMethodName          = "updChgPlateYdStkLyrNo";
		String szMsg                 = "";
		String szOperationName	     = "입고제품검수화면 단정보 변경";
		String szUpdYD_STK_LYR_NO    = "";
		String szCurrYD_STK_LYR_NO   = "";
		String szSTL_NO              = "";
		String szYD_STK_COL_GP       = "";
		String szYD_STK_BED_NO       = "";
		String szCheckSTL_NO         = "";
		String szYD_STK_LYR_MTL_STAT = "";
		int nRet                     = 0;

		
		try {
			for(int x=0;x<inDto.length;x++){				

				// 적치단번호
				szUpdYD_STK_LYR_NO = yddatautil.setDataDefault(inDto[x].getField("YD_STK_LYR_NO"), "");
					
				// 재료번호 
				szSTL_NO = yddatautil.setDataDefault(inDto[x].getField("STL_NO"), "");
				
				
				
				
				
				//======================================================================
				// 현재 적치중인 단의 정보 조회  (GP : 3)
				//======================================================================
				// 레코드 생성
				outRecSet = JDTORecordFactory.getInstance().createRecordSet("");
				recPara   = JDTORecordFactory.getInstance().create();
				recPara.setField("STL_NO"             , szSTL_NO); 
				recPara.setField("YD_STK_LYR_MTL_STAT", "C"); 
				nRet = ydStkLyrDao.getYdStklyr(recPara, outRecSet, 3);
				if(nRet < 0){
					szMsg = "[입고제품검수화면 단정보 변경] 현재 적치중인 단의 정보 조회  조회중  ERROR !!!";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					return ;
				} else if(nRet == 0){
					szMsg = "[입고제품검수화면 단정보 변경] 현재 적치중인 단의 정보 조회  조회 건수가 없음";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					return ;
				} else if(nRet > 0){
					szMsg = "[입고제품검수화면 단정보 변경] 현재 적치중인 단의 정보 조회성공";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);

					outRecSet.first();
					recGetVal = outRecSet.getRecord();
					
					szYD_STK_COL_GP     = ydDaoUtils.paraRecChkNull(recGetVal, "YD_STK_COL_GP");
					szYD_STK_BED_NO     = ydDaoUtils.paraRecChkNull(recGetVal, "YD_STK_BED_NO");
					szCurrYD_STK_LYR_NO = ydDaoUtils.paraRecChkNull(recGetVal, "YD_STK_LYR_NO");
				}

				
				
				
				
				//======================================================================
				// 변경될 적치단 번호에 이미 다른 재료번호가 적치되어 있는지 조회 (GP : 0)
				//======================================================================
				outRecSet = JDTORecordFactory.getInstance().createRecordSet("");
				recPara   = JDTORecordFactory.getInstance().create();
				recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP); 
				recPara.setField("YD_STK_BED_NO", szYD_STK_BED_NO); 
				recPara.setField("YD_STK_LYR_NO", szUpdYD_STK_LYR_NO); 
				nRet = ydStkLyrDao.getYdStklyr(recPara, outRecSet, 0);
				if(nRet < 0){
					szMsg = "[입고제품검수화면 단정보 변경] 변경될 적치단 번호에 이미적치 되어 있는재료가 있는지  정보 조회  조회중  ERROR !!!";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					return ;
				} else if(nRet == 0){
					szMsg = "[입고제품검수화면 단정보 변경] 변경될 적치단 번호에 이미적치 되어 있는재료가 있는지  정보 조회  조회중  건수가 없음";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					return ;
				} else if(nRet > 0){
					outRecSet.first();
					recGetVal = outRecSet.getRecord();
				
					szCheckSTL_NO = ydDaoUtils.paraRecChkNull(recGetVal, "STL_NO");
					szYD_STK_LYR_MTL_STAT = ydDaoUtils.paraRecChkNull(recGetVal, "YD_STK_LYR_MTL_STAT");

					if(!szCheckSTL_NO.equals("") || szYD_STK_LYR_MTL_STAT.equals("C")){					
						szMsg = "[입고제품검수화면 단정보 변경] 변경될 적치단 번호에 이미적치 되어 있는재료가 있음 YD_STK_COL_GP(" + szYD_STK_COL_GP + ") YD_STK_BED_NO(" + szYD_STK_BED_NO + ") YD_STK_LYR_NO(" + szUpdYD_STK_LYR_NO + ") STL_NO(" + szCheckSTL_NO + ") YD_STK_LYR_MTL_STAT(" + szYD_STK_LYR_MTL_STAT + ")";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
						return ;
					}
				}				
				

				

				
				//======================================================================
				// 현재 적치단을 클리어 
				//======================================================================
				paraRec = JDTORecordFactory.getInstance().create();
				paraRec.setField("YD_STK_COL_GP"      , szYD_STK_COL_GP); 
				paraRec.setField("YD_STK_BED_NO"      , szYD_STK_BED_NO); 				
				paraRec.setField("YD_STK_LYR_NO"      , szCurrYD_STK_LYR_NO);				
				paraRec.setField("STL_NO"             , ""); 
				paraRec.setField("YD_STK_LYR_MTL_STAT", "E"); 
				nRet = ydStkLyrDao.updYdStklyr(paraRec, 0);				
				if(nRet <= 0){
					if(nRet == -1){
						szMsg = "Routine Error!!!, ErrorCode:" + nRet;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "Parameter Error!!!, ErrorCode:" + nRet;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}					
				} else {
					szMsg = "[입고제품검수화면 단정보 변경] 현재 적치단을 클리어 성공 YD_STK_COL_GP(" + szYD_STK_COL_GP + ") YD_STK_BED_NO(" + szYD_STK_BED_NO + ") YD_STK_LYR_NO(" + szCurrYD_STK_LYR_NO + ") STL_NO(" + szCheckSTL_NO + ")";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}				
				
				
				
				
				
				//======================================================================
				// 변경될 적치단에 해당재료 업데이트 
				//======================================================================
				paraRec = JDTORecordFactory.getInstance().create();
				paraRec.setField("YD_STK_COL_GP"      , szYD_STK_COL_GP); 
				paraRec.setField("YD_STK_BED_NO"      , szYD_STK_BED_NO); 				
				paraRec.setField("YD_STK_LYR_NO"      , szUpdYD_STK_LYR_NO);				
				paraRec.setField("STL_NO"             , szSTL_NO); 
				paraRec.setField("YD_STK_LYR_MTL_STAT", "C"); 
				nRet = ydStkLyrDao.updYdStklyr(paraRec, 0);				
				if(nRet < 0){
					if(nRet == -1){
						szMsg = "Routine Error!!!, ErrorCode:" + nRet;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "Parameter Error!!!, ErrorCode:" + nRet;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}					
				} else {
					szMsg = "[입고제품검수화면 단정보 변경] 변경될  적치단에 해당재료 업데이트 성공 YD_STK_COL_GP(" + szYD_STK_COL_GP + ") YD_STK_BED_NO(" + szYD_STK_BED_NO + ") YD_STK_LYR_NO(" + szUpdYD_STK_LYR_NO + ") STL_NO(" + szSTL_NO + ")";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}				
			}
		} catch (Exception e){
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally{
		}		
	}		


	
	
	
