	/**
	 * 베드정리작업
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String toBedClear(JDTORecord[] inDto) throws DAOException {
		/*
		 * 업무기준 : 1. 그리드로 넘겨진 정보를 통아여 베드정리작업
		 */
		
		
		//JDTO변수 정의
		JDTORecord      recPara        = null;
		JDTORecord      recTemp        = null;
		
		//기본변수 정의
		String      szMsg        		= "";
		String      szMethodName		= "toBedClear";
		String		szOperationName		= "베드정리작업";
		String		szRtnMsg			= YdConstant.RETN_CD_SUCCESS;
		//로컬변수 정의
	    int			intLOT_SH			= 0;	
		int intRtnVal = 0;
		int intRecCnt = 0;
		
		try {
			intLOT_SH = inDto.length;
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 - 작업 건수["+intLOT_SH+"]";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		
			
			for(int i = 0; i < inDto.length; i++ ) {
				recTemp = JDTORecordFactory.getInstance().create(); 				
				recPara = JDTORecordFactory.getInstance().create();
				
				recTemp = inDto[i];
				
				recPara.setField("STL_NO", ydDaoUtils.paraRecChkNull(recTemp, "STL_NO"));
				recPara.setField("YD_STK_COL_GP", ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_COL_GP"));
				recPara.setField("YD_STK_BED_NO", ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_BED_NO"));
				recPara.setField("YD_STK_LYR_NO", ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_LYR_NO"));
				recPara.setField("MODIFIER", ydDaoUtils.paraRecChkNull(recTemp, "YD_USER_ID"));
				                      
				szRtnMsg = yddatautil.updStkLyrClear(recPara);
				
				
				
				if(szRtnMsg.equals(YdConstant.RETN_CD_SUCCESS)){
					szMsg = "[JSP-SESSION] [ "  + szOperationName +  "]   정보 삭제 성공";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
				} else if(szRtnMsg.equals(YdConstant.RETN_CD_FAILURE)){
					szMsg = "[JSP-SESSION] [ "  + szOperationName +  "]   정보 삭제 실패";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
				}
				
				
			}
	

			szMsg = "[JSP Session : "+szOperationName+"]  - 메소드 끝";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return szRtnMsg;
	}//end of toBedClear
	
	
	
	/**
	 * 이적실적발생
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String toSendDmTcBakcUp(JDTORecord[] inDto) throws DAOException {
		/*
		 * 업무기준 : 1. 그리드로 넘겨진 정보를 통아여 이적실적발생
		 */
		
		
		//JDTO변수 정의
		JDTORecord      recPara        = null;
		JDTORecord      recTemp        = null;
		
		//기본변수 정의
		String      szMsg        		= "";
		String      szMethodName		= "toSendDmTcBakcUp";
		String		szOperationName		= "이적실적발생";
		String		szRtnMsg			= YdConstant.RETN_CD_SUCCESS;
		//로컬변수 정의
	    int			intLOT_SH			= 0;	
		int intRtnVal = 0;
		int intRecCnt = 0;
		
		
		String szStkColGpFrom = null;
		String szStkBedNoFrom = null;
		String szStkLyrNoFrom = null;
		
		
		String szStkColGp = null;
		String szStkBedNo = null;
		String szStkLyrNo = null;
		String szTC_CODE = "";

		String szStlNo = null;
		
		
		String szBEFO_STORE_LOC ="";
		String szTO_STORE_LOC = "";
		
		
		String curDate = YdUtils.getCurDate("yyyyMMddHHmmss");
		
		
		YdDeleComm deleComm = new YdDeleComm();
		YdDelegate		ydDelegate	= new YdDelegate();
		
		
		try {
			intLOT_SH = inDto.length;
			szMsg = "[JSP Session : "+szOperationName+"] 메소드 시작 - 작업 건수["+intLOT_SH+"]";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		
			
			for(int i = 0; i < inDto.length; i++ ) {
				
				
				
				recPara = JDTORecordFactory.getInstance().create(); // 초기화
				recTemp = JDTORecordFactory.getInstance().create(); // 초기화
				
				
				recTemp = inDto[i];
				
				szStlNo = ydDaoUtils.paraRecChkNull(recTemp, "STL_NO");
				szStkColGp = ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_COL_GP");
				szStkBedNo = ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_BED_NO");
				szStkLyrNo = ydDaoUtils.paraRecChkNull(recTemp, "YD_STK_LYR_NO");
				

				//이적작업실적 전송
				
				// BakcUp 작업 실적이라 현위치에서 현위치 정보로 이적하는 실적만 발생시켜준다.
				szStkColGpFrom = szStkColGp;
				szStkBedNoFrom = szStkBedNo;
				szStkLyrNoFrom = szStkLyrNo;
				
				
				szMsg ="[JSP Session"+ szOperationName+ "FROM저장위치[열:"+ szStkColGpFrom +", 베드:"+szStkBedNoFrom+", 단 : "+szStkLyrNoFrom+"] -----> TO저장위치[열:"+ szStkColGp +", 베드:"+szStkBedNo+", 단 : "+szStkLyrNo+"]";				
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				//--2013.03.07 수정 (3기)
				if( szStkColGp.substring(0,1).equals(YdConstant.YD_GP_PLATE_GDS_YARD) 
					|| szStkColGp.substring(0,1).equals(YdConstant.YD_GP_PLATE2_GDS_YARD) ) { //1,2후판제품창고
					szTC_CODE = "YDDMR005";
					
				}else if(szStkColGp.substring(0,1).equals(YdConstant.YD_GP_C_HR_COIL_GDS_YARD) ) {			//코일제품창고
					szTC_CODE = "YDDMR004";
				}
				
				recPara.setField("TC_CODE"        , szTC_CODE);
				recPara.setField("TC_CREATE_DDTT" , curDate);
			
				
				szMsg = "[JSP Session"+ szOperationName +  "FROM 위치 10자리 변경";				
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				szBEFO_STORE_LOC = ydUtils.ParsingStkColGpBedLyr(szStkColGpFrom, szStkBedNoFrom, szStkLyrNoFrom );
				
				if(szBEFO_STORE_LOC.equals("")){
					szMsg ="[JSP Session"+ szOperationName+  "FROM 위치 10자리 변경 실패";				
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}
				
				szMsg = "[JSP Session"+ szOperationName +  "TO 위치 10자리 변경";				
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				szTO_STORE_LOC = ydUtils.ParsingStkColGpBedLyr(szStkColGp, szStkBedNo, szStkLyrNo );
				
				if(szTO_STORE_LOC.equals("")){
					szMsg = "[JSP Session"+ szOperationName +  "TO 위치 10자리 변경 실패";					
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}
				
				
				recPara.setField("GOODS_NO"       , szStlNo);
				recPara.setField("BEFO_STORE_LOC" , szBEFO_STORE_LOC);
				recPara.setField("TO_STORE_LOC"   , szTO_STORE_LOC);
				recPara.setField("MOVENSTACK_DATE", curDate.substring(0, 8));
				recPara.setField("MOVENSTACK_TIME", curDate.substring(8, 14));
				
				szMsg ="[JSP Session "+ szOperationName +  " ]- "+ szTC_CODE +"용 이적작업실적["+szTC_CODE+"]송신 전 ";				
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				ydUtils.displayRecord(szOperationName, recPara);
				
				//deleComm.remoteEaiSnder(recPara);
				ydDelegate.sendMsg(recPara);
				szMsg ="[JSP Session "+ szOperationName +  " ]- " + szTC_CODE+" 용 이적작업실적["+szTC_CODE+"]송신후 ";				
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
			}
	

			szMsg = "[JSP Session : "+szOperationName+"]  - 메소드 끝";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return szRtnMsg;
	}//end of toSendDmTcBakcUp
	
	/**
	 * 후판제품 스케줄기동
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public String trxRunSchedule(JDTORecord[] inDto) throws DAOException {
		int intRtnVal = 0;
		String szMsg= null;
		String szMethodName = null;
		String tempLog = null;
		
		szMsg        = "";
		szMethodName = "trxRunSchedule";
		String szOperationName			= "후판제품 스케줄기동";
		String szYD_GP = "";
		String szYD_SCH_CD		= null;
		String szTC_CD = "";
		String szCRN_SCH_INS_TYPE	= "";
		
		String szYD_EQP_ID			= null;
		
		String szYD_WBOOK_ID		= null;
		
		JDTORecord		recTemp		= null;
		JDTORecord		recPara		= null;
		
		YdDelegate		ydDelegate	= new YdDelegate();
		
		Vector			vYD_SCH_CDs		= new Vector();
		
		String szYD_SCH_PRIOR = "";
		
		////
		//DAO 
		YdWrkbookDao ydWrkbookDao = new YdWrkbookDao();
		
////////////////////////////////////////////////////////////////////////////////////////
// 2024.09.23 로그 개선  START
// 기존 putLog -> putLogNew logId 출력 되게 개선
String logId                     = inDto[0].getFieldString("LOG_ID");   	// logid get

if(ydUtils.isEmpty(logId)) logId = ydUtils.getLogIdNew("T");                // log id 가 비어있는경우 새로 후판 제품 log id 새로 발번

szMsg = "후판제품 스케줄기동(PlateJspSeEJBBean." + szMethodName + ") 시작";
ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
// 2024.09.23 로그 개선  END
////////////////////////////////////////////////////////////////////////////////////////
		
		try {
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 시작 -------------------";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
			
			recTemp		= JDTORecordFactory.getInstance().create();
			
			szTC_CD = "YDYDJ506";
			
			recTemp.setField("JMS_TC_CD", szTC_CD);
			
			//저장위치 좌표설정화면 BED 수정
			for(int x=0;x<inDto.length;x++){

				szYD_SCH_CD  		= inDto[x].getFieldString("YD_SCH_CD");
				szYD_EQP_ID  		= inDto[x].getFieldString("YD_EQP_ID");
				
				szYD_WBOOK_ID  		= inDto[x].getFieldString("YD_WBOOK_ID");

				//------------------------------------------------------------------------------
				//	기본적으로 크레인설비ID와 크레인스케줄코드를 크레인스케줄메인 호출 시 전송
				//------------------------------------------------------------------------------
				recTemp.setField("YD_EQP_ID", szYD_EQP_ID);
				recTemp.setField("YD_SCH_CD", szYD_SCH_CD);
				
				if( !szYD_SCH_CD.equals("") && szYD_SCH_CD.length() == 8 ) {
					//------------------------------------------------------------------------------
					//	차량하차스케줄인 경우에는 작업예약ID를 크레인스케줄메인 호출 시 포함시켜 해당 작업예약이
					//	스케줄기동이 되도록 처리
					//------------------------------------------------------------------------------
					if( szYD_SCH_CD.substring(2, 4).equals("PT") 
						&& szYD_SCH_CD.substring(6, 7).equals("L") ) {				//차량 입고
						//szCRN_SCH_INS_TYPE = "U";
						recTemp.setField("YD_WBOOK_ID", szYD_WBOOK_ID);
						
						szMsg = "[Jsp Session : "+szOperationName+"] 차량하차스케줄 기동 - 작업예약ID["+szYD_WBOOK_ID+"]";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
						ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
					}else{
						//------------------------------------------------------------------------------
						//	같은 스케줄코드로 크레인스케줄메인이 호출되는 것을 방지하기 위해서
						//	이미 전송된 크레인스케줄코드가 존재하는 지를 먼저 체크 후 존재하지 않으면 전송
						//------------------------------------------------------------------------------
						if( vYD_SCH_CDs.contains(szYD_SCH_CD) ) {
							continue;
						}
						
						vYD_SCH_CDs.add(szYD_SCH_CD);
					}
				}else{
					
					if( vYD_SCH_CDs.contains(szYD_SCH_CD) ) {
						continue;
					}
					
					vYD_SCH_CDs.add(szYD_SCH_CD);
				}
				
				
				//------------------------------------------------------------------------------
				// 스케줄 기동전 스케줄 우선순위 값이 존재하는경우 우선순위 값을 넣어서 UPDATE 한다
				//------------------------------------------------------------------------------
				
				szYD_SCH_PRIOR = ydDaoUtils.paraRecChkNull(inDto[x], "YD_SCH_PRIOR");
				
				if(!szYD_SCH_PRIOR.equals("")){
					// 작업 예약 정보 우선순위 변경
					recPara		= JDTORecordFactory.getInstance().create();
					
					recPara.setField("YD_WBOOK_ID", szYD_WBOOK_ID);
					recPara.setField("YD_SCH_PRIOR", szYD_SCH_PRIOR);	
					recPara.setField("MODIFIER", ydDaoUtils.paraRecChkNull(inDto[x], "YD_USER_ID"));
					
					
					ydUtils.displayRecord(szOperationName, recPara); 
					
					intRtnVal =  ydWrkbookDao.updYdWrkbook(recPara, 0);
					
					
					if(intRtnVal< 0){
						szMsg = "[Jsp Session : "+szOperationName+"] 작업예약 UPDATE 실패!!";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
						ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.ERROR, logId);
						throw new DAOException("작업예약 UPDATE 실패");
						
					}else if(intRtnVal == 0 ){
						
						szMsg = "[Jsp Session : "+szOperationName+"] 작업예약 UPDATE 할 항목이 없습니다!!";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
						ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
					}else{
						szMsg = "[Jsp Session : "+szOperationName+"] 작업예약 우선순위 UPDATE 성공!!!";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
						ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
						
					}
				
				}
				
				
				
				
				
				szMsg = "[Jsp Session : "+szOperationName+"] 스케줄기동 시작 - 크레인스케줄메인["+szTC_CD+"] JMS 호출 시작";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
				ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
				
				ydUtils.displayRecord(szOperationName, recTemp);
//SJH040002				
//				ydDelegate.sendMsg(recTemp); 

////////////////////////////////////////////////////////////////////////////////////////
// 2024.09.23 로그 개선  START
// CrnSchSeEJB.procY4CrnSchMain call 시  inRecord 에 logId SET 추가 개선
				recTemp.setField("LOG_ID", logId);
// 2024.09.23 로그 개선  END
////////////////////////////////////////////////////////////////////////////////////////

				EJBConnector ejbConn = new EJBConnector("default", "CrnSchSeEJB", this);
				ejbConn.trx("procY4CrnSchMain", new Class[] { JDTORecord.class },	new Object[] { recTemp });


				
				szMsg = "[Jsp Session : "+szOperationName+"] 스케줄기동 시작 - 크레인스케줄메인["+szTC_CD+"] JMS 호출 완료";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
				ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
				
					
			}		
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 끝 -------------------";
// 2024.09.23 기존 putLog -> putLogNew logId 출력 되게 개선
//			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
			
			
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		
////////////////////////////////////////////////////////////////////////////////////////
// 2024.09.23 로그 개선  START
		szMsg = "후판제품 스케줄기동(PlateJspSeEJBBean." + szMethodName + ") 완료";
		ydUtils.putLogNew(szSessionName, szMethodName, szMsg, YdConstant.INFO, logId);
// 2024.09.23 로그 개선  END
////////////////////////////////////////////////////////////////////////////////////////
		
		return YdConstant.RETN_CD_SUCCESS;
	}	// end of trxRunSchedule
	
	
