			recPara.setField("YD_STK_BED_NO_CD", 		    sSTK_BED);
			
			/*com.inisteel.cim.yd.dao.ydstkcoldao.YdStkcolDao.getPlateYdMoveMgt*/
			intRtnVal = ydStkcolDao.getYdStkcol(recPara,outRecSet,306);
			
