	/**
	 * 후판 사외이송처리  - KA0101 01베드로 등록처리
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updPlateYdMoveMgtPop(JDTORecord[] inDto) throws DAOException {
		int intRtnVal = 0;
		String szMsg= null;
		String szMethodName = null;
		String tempLog = null;
		
		szMsg        	= "";
		szMethodName 	= "updPlateYdMoveMgtPop";
		String szOperationName	= "후판제품 사외이송처리";
		
		JDTORecordSet   rsStock 	= null; 
		JDTORecord		outRecord	= JDTORecordFactory.getInstance().create();
		JDTORecord		recPara		= null;
		JDTORecord 		recStock	= null;

		String szYD_STK_COL_GP	= "";
		String szYD_STK_BED_NO	= "";
		String szYD_STK_LYR_NO  = "";
		String szSTL_NO         = "";
		
		YmEtcDao YmEtcDao     	= new YmEtcDao();
		YdStkColDao ydStkcolDao = new YdStkColDao();
		
		try {
			
			String sCarNo   	= yddatautil.setDataDefault(inDto[0].getField("CAR_NO"), ""); 
			
			/*
			 * 0. 차량정보 보장
			 */
			recPara		= JDTORecordFactory.getInstance().create();
			recPara.setField("CAR_NO", 		 sCarNo);
			recPara.setField("YD_STK_COL_GP","KA0101");
			
			intRtnVal = ydStkcolDao.updYdStkcol(recPara, 0);
			
			/*
			 * 1. 차량단위 정보삭제
			 */
			recPara		= JDTORecordFactory.getInstance().create();
			recPara.setField("CAR_NO", sCarNo);
			
			/* com.inisteel.cim.yd.dao.ymEtcDao.YmEtcDao.updDmFrMvMtl */
			intRtnVal = YmEtcDao.uptYmEtcDao(recPara, 11);
			
			JDTORecord[] inRecord = new JDTORecord[inDto.length];
			
			JDTORecord recPtPara = JDTORecordFactory.getInstance().create();
			recPtPara.setField("JMS_TC_CD",          "YDYDJ297");
			recPtPara.setField("YD_STK_BED_STL_SH",  "" + inDto.length);

			String[] arrStlNo  = new String[inDto.length+1];
			
			for(int x=0;x<inDto.length;x++){
				/*
				 * 1. 진행관리 오버롤 체크
				 */
				//재료번호
				recPtPara.setField("STL_NO" + (x+1), inDto[x].getFieldString("STL_NO"));
				
				/*
				 * 2. KA0101에 저장위치 등록
				 */
				szYD_STK_COL_GP	= "KA0101";
				szYD_STK_BED_NO	= "01";
				szYD_STK_LYR_NO = inDto[x].getFieldString("YD_STK_LYR_NO");
				szSTL_NO 		= inDto[x].getFieldString("STL_NO");
				
				recPara		= JDTORecordFactory.getInstance().create();
				recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP);
				recPara.setField("YD_STK_BED_NO", szYD_STK_BED_NO);
				recPara.setField("YD_STK_LYR_NO", szYD_STK_LYR_NO);
				recPara.setField("STL_NO", 	  	  szSTL_NO);
				
				inRecord[x] = recPara;
								
		    }

			EJBConnector ejbConn = new EJBConnector("default", "SlabJspSeEJB", this);
			ejbConn.trx("updPlateYdStkPosFix", new Class[] { JDTORecord[].class }, new Object[] { inRecord });
			
			// 진행관리 오버롤체크
			{
				//DELEGATE
				YdDelegate ydDelegate = new YdDelegate();
				//전문 송신
				ydDelegate.sendMsg(recPtPara);
				szMsg = "A후판 창고 야드 BOOK_OUT 처리 완료후 오버롤 체크완료!";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			}
			
			outRecord.setField("RTN_CD", "1");
			outRecord.setField("RTN_MSG"," 정상 등록되었습니다.");				
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 끝 -------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return outRecord;
	}	// end of 
	
