	/**
	 * 후판 동별저장계획 수정
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updPlateYdBayLocPlnMgt(JDTORecord[] inDto) throws DAOException {
		
		int intRtnVal 	= 0;
		String szMsg				= "";
		String szMethodName 		= "updPlateYdBayLocPlnMgt";
		String szOperationName		= "후판 동별저장계획 수정";
		
		JDTORecordSet   rsStock 	= null; 
		JDTORecord		outRecord	= JDTORecordFactory.getInstance().create();
		JDTORecord		recPara		= null;
		JDTORecord 		recStock	= null;
		
		String szITEM		= "";
		String szITEM1		= "";
		String szITEM2		= "";
		String szREPR_CD_GP = "";
		String szCD_GP  	= "";
		String szLW_GP  	= "";
		String szFlag       = "";
		
		//DAO 
		YdCarSchDao ydCarSchDao = new YdCarSchDao();
		
		try {
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 시작 -------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			String sYD_USER_ID	= yddatautil.setDataDefault(inDto[0].getField("YD_USER_ID"), ""); //수정자
			
			
			//저장위치 좌표설정화면 BED 수정
			for(int x=0;x<inDto.length;x++){
				for(int i=0;i<7;i++){
					
					if (i == 0) {
						szFlag = "A";
					} else if (i == 1) {
						szFlag = "B";
					} else if (i == 2) {
						szFlag = "C";
					} else if (i == 3) {
						szFlag = "D";
					} else if (i == 4) {
						szFlag = "E";
					} else if (i == 5) {
						szFlag = "F";
					} else if (i == 6) {
						szFlag = "G";
					}					
					szREPR_CD_GP= inDto[x].getFieldString("REPR_CD_GP");
					szCD_GP     = inDto[x].getFieldString("CD_GP");
					szLW_GP     = inDto[x].getFieldString("LW_GP");
					szITEM		= szFlag;
					szITEM1		= inDto[x].getFieldString(szFlag + "_DONG");
					
					if(szFlag.equals("A")) {
						// A동일경우는 UPDATE 수행 안 한다.
						continue;
					} else if(szREPR_CD_GP.startsWith(YdConstant.YD_GP_PLATE_GDS_YARD) && szFlag.equals("G")) {
						//1후판인데 G동일경우는 UPDATE 수행 안 한다.
						continue;
					}
					
					recPara		= JDTORecordFactory.getInstance().create();
					recPara.setField("REPR_CD_GP"	, szREPR_CD_GP);
					recPara.setField("CD_GP"		, szCD_GP);
					recPara.setField("ITEM"			, szLW_GP);      // 구분
					recPara.setField("DONG"			, szITEM);       // 동 
					recPara.setField("ITEM_VALUE1"	, szITEM1);      // 동 값
					recPara.setField("MODIFIER"		, sYD_USER_ID);
					
					/*com.inisteel.cim.yd.dao.ydcarschdao.ydCarSchDao.updPlateYdBayLocPlnMgt*/
					intRtnVal =  ydCarSchDao.updYdCarschYdCarWrkBookId(recPara, 302);
						
					//if(intRtnVal <= 0){
					if(intRtnVal < 0){
						szMsg = "[Jsp Session : "+szOperationName+"] UPDATE 실패!!"+ intRtnVal;
						outRecord.setField("RTN_CD", "0");
						outRecord.setField("RTN_MSG", szMsg);
						return outRecord;
					}
				}	
			}
			
			

			outRecord.setField("RTN_CD", "1");
			outRecord.setField("RTN_MSG"," 정상 등록되었습니다.");				
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 끝 -------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
			
		} catch (Exception e) {
			// Exception발생시 EJBServiceException의 상속클래스로 throw합니다.
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return outRecord;
	}	// end of 
	
	
