	/**
	 * 후판제품야드 적치 좌표 X  수정(EF동) 
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto (YD_STK_COL_GP , 폭변경 정보 )
	 * @return int ( 1 : 수정완료 , 0 ; 수정실패 )
	 * @throws DAOException
	 */
	public int ydStkPosFix_X_EF_insert(JDTORecord inDto) throws DAOException {
		
		int intRtnVal 					= 0;
		String szMsg 					= null;
		String szMethodName 			= "ydStkPosFix_X_EF_insert";
		String szOperationName 			= "후판제품야드 적치 좌표 XEF_insert  수정";
		YdStkBedDao ydStkBedDao 		= new YdStkBedDao();
		YdStkColDao ydStkColDao 		= new YdStkColDao(); 
		
		String szYD_STK_COL_GP_Pre 		= "";
		String szYD_STK_COL_GP_Aft 		= "";
		String szYD_STK_COL_W_GP_New 	= "";
		String szYD_STK_COL_GP 			= "";
		
		int nYD_STK_COL_NO 	= 0;
		int nYD_STK_COL_X 	= 0;
		
		JDTORecord    recPara     = JDTORecordFactory.getInstance().create();	
		JDTORecord    recRtnVal   = JDTORecordFactory.getInstance().create();	
		JDTORecord    recRtnVal1  = JDTORecordFactory.getInstance().create();	
		JDTORecord    recRtnVal2  = JDTORecordFactory.getInstance().create();
		JDTORecord    recRtnVal3  = JDTORecordFactory.getInstance().create();
		JDTORecordSet outRecSet   = JDTORecordFactory.getInstance().createRecordSet("retTmp");
		
		try {
			
			szMsg = "JSP-SESSION ["+ szOperationName +"] 시작";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
			//기존 폭구분 정보 
			intRtnVal = ydStkColDao.getYdStkcol(inDto, outRecSet, 0);
			
			if(intRtnVal >0)
			{
				outRecSet.first();
				recRtnVal = outRecSet.getRecord();
			}
			
			szYD_STK_COL_W_GP_New 	= yddatautil.setDataDefault(inDto.getField("YD_STK_COL_W_GP"), "");
			szYD_STK_COL_GP			= yddatautil.setDataDefault(inDto.getField("YD_STK_COL_GP"), "");
			
			szMsg ="변경 폭구분 " +szYD_STK_COL_W_GP_New ;
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);
			
			szMsg ="야드 적치열 구분 = [ " +szYD_STK_COL_GP + " ]";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);
			
			//사전 정보 조회 
			nYD_STK_COL_NO = Integer.parseInt(yddatautil.setDataDefault(inDto.getField("YD_STK_COL_GP"), "  ").substring(4,6));
			szYD_STK_COL_GP_Pre = szYD_STK_COL_GP.substring(0,4)+YdUtils.fillSpZr(Integer.toString(nYD_STK_COL_NO-1), 2, 0);
			szYD_STK_COL_GP_Aft = szYD_STK_COL_GP.substring(0,4)+YdUtils.fillSpZr(Integer.toString(nYD_STK_COL_NO+1), 2, 0);
			
			//이전 열 정보 읽어오기 
			recPara = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP_Pre);
			
			outRecSet = JDTORecordFactory.getInstance().createRecordSet("retTmp");
			intRtnVal = ydStkColDao.getYdStkcol(recPara, outRecSet, 0);
			
			recRtnVal1   = JDTORecordFactory.getInstance().create();	
			
			if(intRtnVal > 0 ){
				outRecSet.first();
				recRtnVal1 = outRecSet.getRecord();
			}
			
			//이후 열 정보 읽어오기 
			recPara = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP_Aft);
			
			outRecSet = JDTORecordFactory.getInstance().createRecordSet("retTmp");
			intRtnVal = ydStkColDao.getYdStkcol(recPara, outRecSet, 0);
			
			recRtnVal3   = JDTORecordFactory.getInstance().create();	
			
			if(intRtnVal > 0 ){
				outRecSet.first();
				recRtnVal3 = outRecSet.getRecord();
			}
			
			//해당열의 SPAN에서 MAX 열 정보 읽어오기 
			recPara = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP);
			
			outRecSet = JDTORecordFactory.getInstance().createRecordSet("retTmp");
			intRtnVal = ydStkColDao.getYdStkcol(recPara, outRecSet, 22);
			
			recRtnVal2   = JDTORecordFactory.getInstance().create();	
			
			if(intRtnVal > 0 ){
				outRecSet.first();
				recRtnVal2 = outRecSet.getRecord();
			}
			
			// 중폭으로 변경시(M)
			if (YD_STK_COL_W_GP_M.equals(szYD_STK_COL_W_GP_New))
			{
				// 해당스판 마지막열이거나 해당열+1이 적치가능이고해당열-1 열이 사용불가일경우에만 적용
				if(szYD_STK_COL_GP.equals(yddatautil.setDataDefault(recRtnVal2.getField("YD_STK_COL_GP"), ""))||
				   (		
				    YD_STK_COL_ACT_STAT_L.equals(yddatautil.setDataDefault(recRtnVal3.getField("YD_STK_COL_ACT_STAT"),""))&&
				    YD_STK_COL_ACT_STAT_N.equals(yddatautil.setDataDefault(recRtnVal1.getField("YD_STK_COL_ACT_STAT"),""))
				   ) 
				){
					
					nYD_STK_COL_X = Integer.parseInt(yddatautil.setDataDefault(recRtnVal.getField("YD_STK_COL_RULE_XAXIS"), "0")) - 1350;
				}else{
					nYD_STK_COL_X = Integer.parseInt(yddatautil.setDataDefault(recRtnVal.getField("YD_STK_COL_RULE_XAXIS"), "0"));
				}
			}else{
				nYD_STK_COL_X = Integer.parseInt(yddatautil.setDataDefault(recRtnVal.getField("YD_STK_COL_RULE_XAXIS"), "0"));
			}
						
			szMsg ="Start ===================각 BED 별 X좌표 수정 (01,02,03베드)==============";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);
			
			//각 BED 별 X좌표 수정 (01,02,03베드)
			recPara = JDTORecordFactory.getInstance().create();
			
			szMsg ="Start ===================01 BED 설정 ============";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);

			recPara.setField("YD_STK_COL_GP", szYD_STK_COL_GP);
			recPara.setField("YD_STK_BED_NO", YD_STK_BED_NO_1);
			recPara.setField("YD_STK_BED_XAXIS", new Integer(nYD_STK_COL_X));
			
			ydStkBedDao.updYdStkbed(recPara, 0);
							
			szMsg ="Start ===================02 BED 설정 ============";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);

			recPara.setField("YD_STK_BED_NO", YD_STK_BED_NO_2);

			ydStkBedDao.updYdStkbed(recPara, 0);
			
			szMsg ="Start ===================03 BED 설정 ============";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);

			recPara.setField("YD_STK_BED_NO", YD_STK_BED_NO_3);
			
			ydStkBedDao.updYdStkbed(recPara, 0);
			
			szMsg ="Start ===================04 BED 설정 ============";
			ydUtils.putLog(szClassName, szMethodName, szMsg, YdConstant.DEBUG);
		
			recPara.setField("YD_STK_BED_NO", YD_STK_BED_NO_4);

			ydStkBedDao.updYdStkbed(recPara, 0);	
			szMsg = "JSP-SESSION ["+ szOperationName +"] 끝";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
			return 1;			
		} catch (Exception e) {
			// Exception발생시 EJBServiceException의 상속클래스로 throw합니다.
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
			
		}
	}	// end of ydStkPosFix_X_EF_insert
	
