	public JDTORecord updPlateYdSelWrkProcDong(JDTORecord inDto) throws DAOException {
		
		JDTORecord		recPara		= JDTORecordFactory.getInstance().create();
		JDTORecord		outRecord	= JDTORecordFactory.getInstance().create();
		int intRtnVal 	= 0;
		String sGATE				= "";
		String szMsg				= "";
		String szMethodName 		= "updPlateYdSelWrkProcDong";
		String szOperationName		= "후판제품야드 자동선별시작 등록procedure";

		try {
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 시작 -------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
			sGATE = ydDaoUtils.paraRecChkNull(inDto, "GATE");
			
			recPara = JDTORecordFactory.getInstance().create();
			
			
			//--2013.02.27 추가 (3기)
			//recPara.setField("YD_GP",      StringHelper.evl(inDto.getFieldString("YD_GP"), YdConstant.YD_GP_PLATE_GDS_YARD)); 
			//recPara.setField("DONG", 	   sGATE.substring(0,1));
			//recPara.setField("GATE", 	   sGATE.substring(1,2));

			//YdEqpDao 		ydEqpDao 		= new YdEqpDao();		
			
			/*com.inisteel.cim.yd.dao.ydeqpdao.YdEqpDao.ProcedureSelDong*/
			//JDTORecord record = ydEqpDao.ProcedureSelDong(recPara);
			
			//-------------------------------------------------------------------------------------------------------------			
			//조출대상 선별적용 이후 프로시져에 목적지와 상세착지도 파라메터로 넘긴다.
			YdPlateCommDAO  commDao 	  = new YdPlateCommDAO();
			
			recPara.setField("YD_GP"		, ydDaoUtils.paraRecChkNull(inDto, "YD_GP"));
			Object[] inParam = { 
					ydDaoUtils.paraRecChkNull(inDto, "YD_GP")
					,sGATE.substring(0,1)
					,sGATE.substring(1,2)
					,ydDaoUtils.paraRecChkNull(inDto, "CUST_CD")
					,ydDaoUtils.paraRecChkNull(inDto, "DETAIL_ARR_CD")
				   };
			
			int[] inParamIndex = {1,2,3,4,5};
			
			JDTORecord record = commDao.callProcedure(inParam, inParamIndex, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.callSpQueryId_0005_PIDEV");
			//-------------------------------------------------------------------------------------------------------------			
			
			if(record == null || record.size() <= 0){
				
				outRecord.setField("RTN_CD", "0");
				outRecord.setField("RTN_MSG"," 프로시져 호출 이상.");	
				return outRecord;
			} else {
				
				String sOUT_RTN_CODE =  ydDaoUtils.paraRecChkNull(record, "OUT_RTN_CODE");
				if(sOUT_RTN_CODE.length() == 14){
					YdDelegate ydDelegate = new YdDelegate();	
					recPara = JDTORecordFactory.getInstance().create();
					recPara.setField("JMS_TC_CD", "YDYDJ506");
					recPara.setField("YD_SCH_CD", sOUT_RTN_CODE.substring(0,8));
					//작업크레인 정보를 설비에 넣어준다. 
					recPara.setField("YD_EQP_ID", sOUT_RTN_CODE.substring(8,14) );
					
					szMsg = "[sOUT_RTN_CODE : "+sOUT_RTN_CODE;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);												
					
					ydDelegate.sendMsg(recPara);
				}	
			
			}	
			outRecord.setField("RTN_CD", "1");
			outRecord.setField("RTN_MSG"," 정상 등록되었습니다.");				
			
			szMsg = "[Jsp Session : "+szOperationName+"] ------------------- 메소드 끝 -------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
			
			
		} catch (Exception e) {
			// Exception발생시 EJBServiceException의 상속클래스로 throw합니다.
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} finally {
		}
		return outRecord;
	}	// end of

