	/**
	 * 일관제철 3기 - GridData - 단순 Update 
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public void updGridData(JDTORecord[] inDto, String queryId) throws DAOException {
		
		int intRtnVal = 0;
		String szMsg= "";
		String szMethodName = "updGridData";
		String szYD_CARPNT_CD= "";
		JDTORecord recPara   = null;  		
		
		String szFieldName = null;
		Iterator itrFieldName = null;	
		
		YdPlateCommDAO commDao = new YdPlateCommDAO();
		
		try {
			
			recPara   = JDTORecordFactory.getInstance().create();
			
			for(int ii=0 ; ii < inDto.length ; ii++){
				
				//필드명을 가져온다.
				itrFieldName = inDto[ii].iterateName();
				
				//필드명 갯수만큼 루프를 돈다.
				while(itrFieldName.hasNext()) {
					
					szFieldName = (String)itrFieldName.next();
					
					recPara.setField(szFieldName, yddatautil.setDataDefault(inDto[ii].getField(szFieldName),"") );
				}
				
				//dao 호출
				/*
				 * com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_0003 //이송재료 LIST - 수정 (목표행선/야드/동 변경)
				 * com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_0004 //반납 LIST - 수정 (PLNT_PROC_CD:공장공정코드 변경)
				 * 
				 */
				intRtnVal = commDao.update(recPara, queryId);
				
				if (intRtnVal < 0) {
					if (intRtnVal == -1) {
						szMsg = "routine error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					} else {
						szMsg = "parameter error!!!, ErrorCode:" + intRtnVal;
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
					}
				} 	
				
				//열연 포인트 변경 시 차량 입동포인트 일괄 변경 작업 
				if(queryId.equals("com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_0041")){
					
					szYD_CARPNT_CD 	 = recPara.getFieldString("YD_CARPNT_CD");
					szYD_CARPNT_CD	= szYD_CARPNT_CD.substring(0 , 1);
					
					szMsg = "routine  szYD_CARPNT_CD:>>>>>>>>>>>" + szYD_CARPNT_CD;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
					
					if(szYD_CARPNT_CD.equals("J")){
						//C열연 인경우 
						queryId ="com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_052";
					}else{
						//AB열연 인경우 
						queryId ="com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_053";
					}
					intRtnVal = commDao.update(recPara, queryId);
					
					if (intRtnVal < 0) {
						if (intRtnVal == -1) {
							szMsg = "routine error!!!, ErrorCode:" + intRtnVal;
							ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
						} else {
							szMsg = "parameter error!!!, ErrorCode:" + intRtnVal;
							ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
						}
					} 
				}
				else if (queryId.equals("com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateYdRule2")){  //동별 우선순위 변경작업
					if(ii==(inDto.length-1))  //마지막 데이터까지 업데이트시 기준 한번만 수행한다.
					{  
						JDTORecord recInPara = JDTORecordFactory.getInstance().create();
						recInPara.setField("YD_BAY", "DONG");//동별 우선순위 기준 L2전송
						this.getPlateRtPriority(recInPara); //RT우선순위 L2전송 호출
					}
				}
			
			}
			
		} catch (Exception e) {
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		} 
		
	}	// end of updGridData	
	

	
