	/**
	 *  후판제품야드 차량이송실적등록
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return JDTORecordSet
	 * @throws DAOException
	 */	
	public JDTORecord regCarFrmvWr(GridData gdReq) throws DAOException {
		
		YdSlabUtils slabUtils = new YdSlabUtils();
		
		String methodNm = "[PlateJspSeEJBBean.regCarFrmvWr]";
		String logId = gdReq.getIPAddress();
		String szLogMsg = ""; 
		
		try {
			
			szLogMsg = "JSP-FACADE [ " + methodNm +"] 시작";
			ydUtils.putLog(szSessionName, methodNm, szLogMsg, YdConstant.INFO);			
			
			int intRtnVal 	= 0;
			
			//Return Value
			JDTORecord jrRtn = null;
			YdPlateCommDAO 	commDao 	= new YdPlateCommDAO(); //3기 후판제품공용dao
			
			JDTORecordSet 	rsResult	= null;
			JDTORecord		recParam	= null;
			JDTORecord		recTemp		= null;
			
			String szMsg = null;
			
			String szSTL_NO				= null;
			String szYD_STK_COL_GP		= null;
			String szYD_STK_LYR_NO		= null;
			
			//------------------------------------------------------------------
			//화면으로 부터 전달 받은 정보
			String szTEL_NUM			= StringHelper.evl(gdReq.getParam("TEL_NUM"),"00000000000");
			
			
			//------------------------------------------------------------------
			//이송실적 등록 가능한 적치열 구분을 조회한다.
			recParam = JDTORecordFactory.getInstance().create();
			rsResult = JDTORecordFactory.getInstance().createRecordSet("");
			
			recParam.setField("YD_STK_COL_GP", "P_PT");
			
			intRtnVal = commDao.select(recParam, rsResult, "com.inisteel.cim.yd.common.dao.YdPlateCommDAO.selectQueryId_0125");
			
			if(intRtnVal<=0) {
				szMsg="["+methodNm+"] PAPT01, PBPT01 차량포인트가 모두 작업대료가 존재합니다! 작업 확인 후 다시 실행해 주세요! - intRtnVal : " + intRtnVal;
				ydUtils.putLog(szSessionName, methodNm, szMsg, YdConstant.ERROR);
				throw new Exception(szMsg);
			}
			
			rsResult.first();
			recTemp			= rsResult.getRecord();
			
			szYD_STK_COL_GP	= StringHelper.evl(recTemp.getFieldString("YD_STK_COL_GP"), "");		
			
			
			//-------------------------------------------------------------------
			// 01 Bed 에 재료번호를 등록한다.
			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();

			for (int ii = 0; ii < rowCnt; ii++) {
				
				szSTL_NO 		= slabUtils.trim(gdReq.getHeader("STL_NO").getValue(ii));
				szYD_STK_LYR_NO = slabUtils.getLPad(slabUtils.trim(gdReq.getHeader("YD_STK_LYR_NO").getValue(ii)),3,"0");

				
				//이전위치 정보 Clear 
				recParam.setField("STL_NO"				, szSTL_NO); 
				recParam.setField("YD_STK_COL_GP"		, slabUtils.trim(gdReq.getHeader("FR_YD_STK_COL_GP").getValue(ii))); 
				recParam.setField("YD_STK_BED_NO"		, slabUtils.trim(gdReq.getHeader("FR_YD_STK_BED_NO").getValue(ii))); 
				
				intRtnVal = commDao.update(recParam, "com.inisteel.cim.yd.common.dao.YdPlateCommDAO.updateQueryId_0025");

				//새위치 등록
				recParam.setField("STL_NO"				, szSTL_NO); 
				recParam.setField("YD_STK_COL_GP"		, szYD_STK_COL_GP); 
				recParam.setField("YD_STK_BED_NO"		, "01"); 
				recParam.setField("YD_STK_LYR_NO"		, szYD_STK_LYR_NO); 
				
				intRtnVal = commDao.update(recParam, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.updateQueryId_0014");
			}
			
			//-------------------------------------------------------------------
			// 02 Bed 에 운전자 핸드폰 번호를 등록한다.
			recParam.setField("STL_NO"				, szTEL_NUM); 
			recParam.setField("YD_STK_COL_GP"		, szYD_STK_COL_GP); 
			recParam.setField("YD_STK_BED_NO"		, "02"); 
			recParam.setField("YD_STK_LYR_NO"		, "001"); 
			
			intRtnVal = commDao.update(recParam, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.updateQueryId_0014");
			
			
			//--------------------------------------------------------------------------
			szLogMsg = "JSP-FACADE [ " + methodNm +"] 끝";
			ydUtils.putLog(szSessionName, methodNm, szLogMsg, YdConstant.INFO);			
			
			return jrRtn;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} //regCarFrmvWr
	
