	/**
	 * IFTest 전송
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord sndIfTest(GridData gdReq) throws DAOException {
		String methodNm = gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		YdSlabUtils ydSlabUtils = null;
		YdPlateCommDAO commDao = null;
		try {
			commDao		= new YdPlateCommDAO();
			ydSlabUtils = new YdSlabUtils();
			ydSlabUtils.printLog(logId, methodNm, "S+", gdReq);

			//Return Value
			JDTORecord jrRtn = null;

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = ydSlabUtils.getParam(logId, methodNm, ydSlabUtils.trim(gdReq.getParam("userid")));

			//레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			String msgId = ydSlabUtils.trim(gdReq.getParam("IF_ID")); //IFID
			
			for (int ii = 0; ii < rowCnt; ii++) {
				
				jrParam.setField("ITM_VAL"	, gdReq.getHeader("ITM_VAL").getValue(ii)); 
				jrParam.setField("IF_ID"	,msgId); 
				jrParam.setField("ITM_SEQ"	, gdReq.getHeader("ITM_SEQ").getValue(ii)); 
				
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updIfTestData");
			}

			String szMsg      = "";
			String ifClassNm  = "";
			String ifMthNm    = "";
			String ifSndRcvGp = "";
			String ifMthGp    = "";
			String szDate = DateHelper.format(new java.util.Date(System.currentTimeMillis()), "yyyy/MM/dd HH:mm:ss");
			
			//ifMthGp  		= msgId.substring(4, 5); //IF방법구분(L:EAI, 기타:JMS)
			ifMthGp    		= gdReq.getParam("MTH_GP");
			//ifSndRcvGp 	= "YM".equals(msgId.substring(0, 2)) ? "S" : "R"; //IF송수신구분(송신, 수신)
			ifSndRcvGp 		= gdReq.getParam("SNDRCV_GP");

			ydSlabUtils.printLog(logId, "*msgId:"+msgId+ " ifSndRcvGp:"+ ifSndRcvGp+ " ifMthGp:"+ ifMthGp, "SL");
			
			//큐에 넣을 데이터를 생성 - Log ID, Method, 수정자 Set
			JDTORecord sndData = ydSlabUtils.getParam(logId, methodNm, ydSlabUtils.trim(gdReq.getParam("userid")));

			sndData.setResultCode(logId);	//Log ID
			sndData.setResultMsg(methodNm);	//Log Method Name			
			sndData.setField("JMS_TC_CD"         , msgId                    );
			sndData.setField("JMS_TC_CREATE_DDTT", szDate);  
			
			if ("E".equals(ifMthGp) && "S".equals(ifSndRcvGp)) {
				//EAI송신처리 일 경우
				ifClassNm = "YmCommEJB";
				ifMthNm   = "sndToEAI";
				ydSlabUtils.printLog(logId, ""+ ifMthGp, "SL");

				//EAI전문 Message
				StringBuffer sbMsg = new StringBuffer();

				for (int ii = 0; ii < rowCnt; ii++) {

					sbMsg = sbMsg.append(gdReq.getHeader("ITM_VAL").getValue(ii));
					ydSlabUtils.printLog(logId, ii+"=="+ sbMsg, "SL");
				}
				sndData.setField("JMS_TC_MESSAGE", sbMsg.toString());
				
			} else {
				if("Y".equals(gdReq.getParam("EFF_YN_TEST"))) {  //신규모듈 적용여부 테스트 

					//신규모듈 적용여부 테스트 CheckBox 체크시 TB_YM_Z_IF 테이블의 BEF_PGM_NM1, BEF_PGM_NM2 을 읽어 호출 한다.
					ifClassNm = gdReq.getParam("BEF_PGM_NM1");
					ifMthNm   = gdReq.getParam("BEF_PGM_NM2");	//EJB Call
					
					szMsg="[ (BEF)"+methodNm+"] ifClassNm:" + ifClassNm + " , ifMthNm:" + ifMthNm ;
					ydSlabUtils.printLog(logId, szMsg, "SL");			    		
					
				} else {
					//수신 처리방법(Q:JMS Queue, E:EJB Call)이 'E'이고 수신처가 야드이면
					if ("E".equals(gdReq.getParam("TRT_MTH")) ) {
						ifClassNm = gdReq.getParam("P_PGM_NM1");
						ifMthNm   = gdReq.getParam("P_PGM_NM2");	//EJB Call
						
					} else {
						ifClassNm = "PSlabYdCommEJB";
						ifMthNm = "sndToJMS";		//JMS송신
					}
				}
				
				//EAI송신 외 처리 일 경우
				for (int ii = 0; ii < rowCnt; ii++) {
					if(!"".equals(ydSlabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)))) {
					//	ydSlabUtils.printLog(logId, ydSlabUtils.trim(gdReq.getHeader("ITM_ID" ).getValue(ii))
					//	  +"(" +ii +")"+" --->" + ydSlabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)) , "SL");
					}
					sndData.setField(ydSlabUtils.trim(gdReq.getHeader("ITM_ID" ).getValue(ii))
							       , ydSlabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)));
				}
			}
			
			//++++++++++++++++++++  ydEjbCon.trx("PSlabYdCommEJB", "rcvInterface", inRecord);
			//송신 공통 EJB를 이용하여 전송
			EJBConnector ejbConn = new EJBConnector("default", ifClassNm, this);
			ejbConn.trx(ifMthNm, new Class[] { JDTORecord.class }, new Object[] { sndData });
			
			ydSlabUtils.printLog(logId, methodNm, "S-");

			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(ydSlabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} // end of sndIfTest
	
	
	/**
	 * IFTest EAI전송
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public GridData sndIfTestEAI(GridData gdReq) throws DAOException {
		String methodNm =   gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		YdSlabUtils slabUtils = null;
		try {
			slabUtils = new YdSlabUtils();
			slabUtils.printLog(logId, methodNm, "S+", gdReq);

			String tcList = gdReq.getParam("TC_LIST"); //전송List
			String tcMsg  = ""; //전송Data
			int sndCnt = 0; //전송건수
			
			slabUtils.printLog(logId, "(in)"+tcList, "SL");

			while (tcList.length() > 0) {
				int idx = tcList.indexOf("\r\n");
				
				if (idx > 0) {
					tcMsg  = tcList.substring(0, idx);
					tcList = tcList.substring(idx + 2);
				} else {
					tcMsg = tcList;
					tcList = "";
				}

				//한건 전송
				if (!"".equals(tcMsg) && tcMsg.length() > 60) {
					//큐에 넣을 데이터를 생성 - Log ID, Method, 수정자 Set
					JDTORecord sndData = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));

					sndData.setResultCode(logId);	//Log ID
					sndData.setResultMsg(methodNm);	//Log Method Name
					//EAI송신처리 일 경우
					sndData.setField("JMS_TC_CD"         , tcMsg.substring(0, 8));
					sndData.setField("JMS_TC_CREATE_DDTT", slabUtils.getDateTime14());
					sndData.setField("JMS_TC_MESSAGE"    , tcMsg);

					//송신 공통 EJB를 이용하여 L2로 전송
					EJBConnector ejbConn = new EJBConnector("default", "PSlabYdCommEJB", this);
					ejbConn.trx("sndToEAI", new Class[] { JDTORecord.class }, new Object[] { sndData });

					sndCnt++;
				}
			}

			gdReq.addParam("SND_CNT", String.valueOf(sndCnt));
			
			slabUtils.printLog(logId, methodNm, "S-");

			return gdReq;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	}
	
	/**
	 *  하차작업등록 (반품,회송,부분하차)
	 *   - 대기장 도착(B)상태로 처리하며, 만약 하차지가 비어 있다면 입동지시 후 
	 *   차량형상여부에 따라서 크레인스케쥴까지 생성한다.
	 *   
	 *   관련저장내역
	 *    - 차량스케쥴, 차량이송재료, 저장품
	 *  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return JDTORecordSet
	 * @throws DAOException
	 */	
	public JDTORecord regCarUdWrk(GridData gdReq) throws DAOException {
		YdSlabUtils ydSlabUtils = new YdSlabUtils();	
		YdPlateCommDAO commDao		= new YdPlateCommDAO();
		String methodNm = "하차작업등록[PlateJspSeEJB.regCarUdWrk] < " + gdReq.getNavigateValue();
		String logId = ydSlabUtils.getLogId();
	    String szMsg = "";
		YdCarSchDao ydCarSchDao = null;	//차량스케줄DAO
		
		try {
			
			ydSlabUtils.printLog(logId, methodNm, "S+", gdReq);	
			
			
			JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
			JDTORecordSet 	rsResult	= null;
			JDTORecord		recParam	= null;
			JDTORecord		recTemp		= null;
			
			String szStlNo 			= null;
			String szCAR_KIND 		= "";
			String szYD_STK_COL_GP 	= null;
			String szTRANS_ORD_DATE = null;
			String szTRANS_ORD_SEQNO = null;
			String szWLOC_CD = ""; 
			String szYD_PNT_CD = "";
			
			//------------------------------------------------------------------
			//화면으로 부터 전달 받은 정보
			String szCAR_NO 		= gdReq.getParam("CAR_NO").toUpperCase();
			String szTEL_NO			= StringHelper.evl(gdReq.getParam("DRIVER_TEL_NO"),"");
			String szDRIVER_NAME	= StringHelper.evl(gdReq.getParam("DRIVER_NAME"),"");
			String szCARD_NO		= StringHelper.evl(gdReq.getParam("CARD_NO"),"").toUpperCase(); //차량번호의 뒤의 4자리를 사용한다.
			String szUser			= gdReq.getParam("YD_USER_ID");
			//------------------------------------------------------------------
			
			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			ydCarSchDao = new YdCarSchDao();	//차량스케줄DAO
			String sTmpYdToLocGuide = "";
			for (int i = 0; i < rowCnt; i++) {
				szStlNo       = ydSlabUtils.trim(gdReq.getHeader("STL_NO").getValue(i));
				
				// 재료번호가 존재하는 것들만 처리한다.
				if(!"".equals(szStlNo)){
					
					// 전달받은 재료번호와 차량 번호로 TB_YD_CARSCH 조회
					recTemp = JDTORecordFactory.getInstance().create();
					rsResult = JDTORecordFactory.getInstance().createRecordSet("");
					recTemp.setField("CAR_NO",         szCAR_NO);
					recTemp.setField("STL_NO",         szStlNo);
					sTmpYdToLocGuide = ydSlabUtils.trim(gdReq.getHeader("YD_TO_LOC_GUIDE").getValue(i));
					if(!"".equals(sTmpYdToLocGuide)){
						if(!sTmpYdToLocGuide.startsWith("T")){
							sTmpYdToLocGuide = YdConstant.YD_GP_PLATE2_GDS_YARD + sTmpYdToLocGuide;
						}
					}
					ydSlabUtils.printLog(logId, methodNm, "차량스케줄조회");
				    if (commDao.select(recTemp, rsResult, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.getYdCarYdCarMtlDEL_YN") > 0) {
						throw new Exception(rsResult.getRecord(0).getFieldString("ERROR_MSG"));
				    }
				}
			}
			
			//CARD_NO가 NULL인경우 차량번호 뒤에 4자리로 셋팅
			if("".equals(szCARD_NO) && szCAR_NO.length() >= 4)
			{
				szCARD_NO = szCAR_NO.substring(szCAR_NO.length()-4, szCAR_NO.length());
			}

			
			//------------------------------------------------------------------
			//운송지시일자, 순번 생성  (999001 처럼 앞에  999를 붙인다.)
			rsResult = JDTORecordFactory.getInstance().createRecordSet("");
			recParam = JDTORecordFactory.getInstance().create();
			ydSlabUtils.printLog(logId, methodNm, "운송지시 일자 생성");
			if (commDao.select(recParam, rsResult, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.getRetnTransOrdNo") < 1) {
				szMsg="운송지시일자,순번  생성시  오류발생 실패!! ";
				throw new Exception(szMsg);
			}
			
			rsResult.first();
			recTemp	= rsResult.getRecord();
			
			szTRANS_ORD_DATE 	=  ydSlabUtils.trim(recTemp.getFieldString("TRANS_ORD_DATE"));
			szTRANS_ORD_SEQNO 	=  ydSlabUtils.trim(recTemp.getFieldString("TRANS_ORD_SEQNO"));
			

			JDTORecord jrParam = JDTORecordFactory.getInstance().create();
			jrParam.setResultCode(logId);	//Log ID
			jrParam.setResultMsg(methodNm);	//Log Method Name
			jrParam.setField("MODIFIER" 		, szUser);
			jrParam.setField("STOCK_MOVE_TERM" 	, "CS");
			jrParam.setField("TRANS_ORD_DATE" 	, szTRANS_ORD_DATE);
			jrParam.setField("TRANS_ORD_SEQNO" 	, szTRANS_ORD_SEQNO);
			jrParam.setField("CAR_CARD_NO" 		, szCARD_NO);
			jrParam.setField("CAR_NO" 			, szCAR_NO);
			jrParam.setField("YD_STK_LOT_CD" 	, szTEL_NO);
			
			jrParam.setField("TRANS_WORD_NO" 	, szTRANS_ORD_SEQNO+szTRANS_ORD_SEQNO);
			String sStlNo  = "";
			
			ydSlabUtils.printLog(logId, methodNm, "반품정보 저장품저장");
			String sTmpYdStkColGp = "";  
			sTmpYdToLocGuide = "";
			
			for (int i = 0; i < rowCnt; i++) {
				sStlNo = ydSlabUtils.trim(gdReq.getHeader("STL_NO").getValue(i));
				if ("".equals(sStlNo)) {
					break;
				}
				
				sTmpYdStkColGp = ydSlabUtils.trim(gdReq.getHeader("YD_STK_COL_GP").getComboHiddenValues()[gdReq.getHeader("YD_STK_COL_GP").getSelectedIndex(i)]);
				if(null == sTmpYdStkColGp || "NULL".equals(sTmpYdStkColGp.toUpperCase())){
					sTmpYdStkColGp = "";
				}
				
				sTmpYdToLocGuide = ydSlabUtils.trim(gdReq.getHeader("YD_TO_LOC_GUIDE").getValue(i));
				if(!"".equals(sTmpYdToLocGuide)){
					if(!sTmpYdToLocGuide.startsWith("T")){
						sTmpYdToLocGuide = YdConstant.YD_GP_PLATE2_GDS_YARD + sTmpYdToLocGuide;
					}
				}
				
				// TB_YD_STOCK
				// YD_RCPT_PLN_STR_LOC : 사용자지정 입고예정위치, YD_RCPT_PLN_STR_LOC1 : 사용자지정 차량포인트
				jrParam.setField("STL_NO",				sStlNo);
				jrParam.setField("YD_CAR_UPP_LOC_CD",			ydSlabUtils.trim(gdReq.getHeader("YD_STK_LYR_NO").getValue(i))); // 차상위치
				jrParam.setField("YD_TO_LOC_GUIDE",				sTmpYdToLocGuide);
				jrParam.setField("YD_STK_LYR_NO",				ydSlabUtils.trim(gdReq.getHeader("YD_STK_LYR_NO").getValue(i))); // 차상위치

				jrParam.setField("YD_RCPT_PLN_STR_LOC",			sTmpYdToLocGuide); // 화면에서 지정한 저장위치
				jrParam.setField("YD_RCPT_PLN_STR_LOC1",		sTmpYdStkColGp); // 화면에서 지정한 차량포인트
	    		commDao.update(jrParam, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.updStockByRetnTrgtGdsPlateInfo");
			}
			
			jrParam.setField("TRANS_ORD_DATE" 	, szTRANS_ORD_DATE);
			jrParam.setField("TRANS_ORD_SEQNO" 	, szTRANS_ORD_SEQNO); 
			jrParam.setField("CAR_NO" 			, szCAR_NO);
			// 저장품의 Layer정보를 다시 재편성하자.
			commDao.update(jrParam, "com.inisteel.cim.yd.common.dao.YdPlateCommDao.updStockByRetnTrgtGdsPlateInfo2");
			
			//------------------------------------------------------------------------
			//차량스케쥴 생성전 입력한 재료의 우선순위별 차량정지위치를 구한다.	
			rsResult = JDTORecordFactory.getInstance().createRecordSet("");
			jrParam = JDTORecordFactory.getInstance().create();
			jrParam.setField("CAR_NO",           		szCAR_NO);
			jrParam.setField("TRANS_ORD_DATE",   		szTRANS_ORD_DATE);
			jrParam.setField("TRANS_ORD_SEQNO",  		szTRANS_ORD_SEQNO);
			if (commDao.select(jrParam, rsResult, "com.inisteel.cim.yd.common.dao.YdPlateCommDAO.getYdCarUnloadStopLocByFirst") < 1) {
				szMsg="대기장 도착처리시 오류[차량정지위치를 찾을 수 없습니다.]";
				throw new Exception(szMsg);
			}
		
			szYD_PNT_CD = rsResult.getRecord(0).getFieldString("YD_PNT_CD");
			szWLOC_CD  = rsResult.getRecord(0).getFieldString("WLOC_CD");
			szYD_STK_COL_GP = rsResult.getRecord(0).getFieldString("YD_CARUD_STOP_LOC");

			
			//------------------------------------------------------------------------
			//차량스케줄 생성 전에 입동대기중인 차량들에서 IF_SEQ_NO MAX값을 읽어온다. 
			rsResult = JDTORecordFactory.getInstance().createRecordSet("");
			jrParam = JDTORecordFactory.getInstance().create();
			jrParam.setField("WLOC_CD"		, szWLOC_CD);
			jrParam.setField("YD_GP"		, szYD_PNT_CD.substring(0,1));
			jrParam.setField("YD_BAY_GP"	, szYD_PNT_CD.substring(1,2));
			
			String szUNIQUE_ID = "0";
			if(commDao.select(jrParam, rsResult, "com.inisteel.cim.yd.common.dao.YdPlateCommDAO.selectQueryId_0082") > 0) {
				szUNIQUE_ID		= rsResult.getRecord(0).getFieldString("IF_SEQ_NO");
			}

		    //--------------------------------------------------------------------------
			//차량스케줄 생성
			String ydCarSchId = ydCarSchDao.getYdCarschId();
    		JDTORecord recInTemp = JDTORecordFactory.getInstance().create();
			
			recInTemp = JDTORecordFactory.getInstance().create();
			recInTemp.setField("YD_CAR_SCH_ID",    		ydCarSchId);
			recInTemp.setField("REGISTER",         		szUser);
			recInTemp.setField("YD_EQP_WRK_STAT",  		"L");									//야드설비작업상태
			recInTemp.setField("YD_EQP_ID",        		YdConstant.YD_DM_CAR_EQP_ID);			//야드설비ID
			recInTemp.setField("YD_CAR_USE_GP",    		YdConstant.YD_CAR_USE_GP_DM);			//차량사용구분
			recInTemp.setField("CAR_KIND", 				StringHelper.evl(szCAR_KIND, "TR"));
			recInTemp.setField("SPOS_WLOC_CD",     		szWLOC_CD);								//발지개소코드
			recInTemp.setField("ARR_WLOC_CD",     		szWLOC_CD);								//발지개소코드
			
			recInTemp.setField("YD_PNT_CD3",     		szYD_PNT_CD);							//야드포인트코드3
			recInTemp.setField("CAR_NO",           		szCAR_NO);								//차량번호
			recInTemp.setField("CARD_NO",          		szCARD_NO);								//카드번호
			recInTemp.setField("YD_CARUD_LEV_DT",  		YdUtils.getCurDate("yyyyMMddHHmmss"));	//상차출발일시
			recInTemp.setField("TRANS_ORD_DATE",   		szTRANS_ORD_DATE);						//운송지시일자
			recInTemp.setField("TRANS_ORD_SEQNO",  		szTRANS_ORD_SEQNO);						//운송지시순번
	    	recInTemp.setField("YD_CARUD_STOP_LOC",		szYD_STK_COL_GP);						//차량하차정지위치
    		//25.03.14 임진후 기사 요청 반품차량은 1순위로 들어오게끔 수정 - 한장만작업하면 되는데 과도하게 기다리는 경우 있다. 
	    	recInTemp.setField("YD_BAYIN_WO_SEQ",  		"1");	//입동지시순번 --기본값으로 설정(9) **
	    	//recInTemp.setField("YD_BAYIN_WO_SEQ",  		YdConstant.YD_BAYIN_WO_SEQ_DEFAULT);	//입동지시순번 --기본값으로 설정(9) **
			recInTemp.setField("YD_CAR_PROG_STAT", 		YdConstant.YD_CARUD_LEV);									//하차출발상태
			recInTemp.setField("IF_SEQ_NO", 			szUNIQUE_ID);							//운송지시 SEQ
			
			recInTemp.setField("YD_CAR_WRK_GP",    		"1");                                   //1: 내수
			recInTemp.setField("TEL_NO", 		   		szTEL_NO);								//기사핸드폰번호
			recInTemp.setField("DRIVER_NAME", 		   	szDRIVER_NAME);								//기사핸드폰번호
			
			
			recInTemp.setField("CMBN_CARLD_YN",    		"");									//첫번째 도착창고 : S 두번째 도착창고 : E
			recInTemp.setField("WAIT_ARR_DDTT",    		YdUtils.getCurDate("yyyyMMddHHmmss"));	//대기장도착시간
			recInTemp.setField("WAIT_ARR_GP",      		"B");									//대기장도착구분  - B:BACKUP , S:SMARTPHONE		
			
    		//차량스케줄 등록
	    	ydCarSchDao.insYdCarsch(recInTemp);
	    	

			// 저장품테이블을 조회하여 이송재료를 만든다.
			recInTemp = JDTORecordFactory.getInstance().create(); 
			recInTemp.setField("TRANS_ORD_DATE",   		szTRANS_ORD_DATE);						//운송지시일자
			recInTemp.setField("TRANS_ORD_SEQNO",  		szTRANS_ORD_SEQNO);						//운송지시순번
			recInTemp.setField("CAR_NO",  		szCAR_NO);						//운송지시순번
			ydSlabUtils.printLog(logId, methodNm, "차량재료 스케쥴 INSERT");
			commDao.update(recInTemp, "com.inisteel.cim.yd.common.dao.YdPlateCommDAO.insYdCarftmvmtl");	

			//3.차량스케줄재료 생성
			if( rowCnt > 0){
				List aSendMsg = new ArrayList();
				for (int ii = 0; ii < rowCnt; ii++) {
					szStlNo       = ydSlabUtils.trim(gdReq.getHeader("STL_NO"    ).getValue(ii)); 
					if ("".equals(szStlNo)) {
						JDTORecord sndL2Msg = JDTORecordFactory.getInstance().create();
						sndL2Msg.setField("TC_CD"          , "YDY8L002");
						
						if(PlateGdsYdUtil.isSendToEaiY9_ydStkColGp(szYD_STK_COL_GP)){
							sndL2Msg.setField("TC_CD"          , "YDY9L002");
						}
						sndL2Msg.setField("MSG_GP"         , "I");
						sndL2Msg.setField("YD_INFO_SYNC_CD", "R");
						sndL2Msg.setField("STL_NO"       , szStlNo);
						
						aSendMsg.add(sndL2Msg);
//						ydDelegate.sendMsg(sndL2Msg);
					}
				}
				jrRtn.setField("SEND_DATA", aSendMsg);
			}

			/*
			 * 6. 차량정지위치에대한 입동대기차량들중에서 가장빠른 입동순서를 가진 차량을 입동지시하는 차량입동지시요구 모듈을 호출한다.
			 */
			szMsg=" 차량정지위치[" + szYD_STK_COL_GP + "], 차량스케줄ID[" + ydCarSchId + "] - 차량입동지시요구 모듈을 EJB 호출 시작";
			ydSlabUtils.printLog(logId, methodNm, szMsg);
			JDTORecord sendYDYDJ633 = JDTORecordFactory.getInstance().create();
			sendYDYDJ633.setField("TC_CODE"				,"YDYDJ633");
			sendYDYDJ633.setField("TC_CREATE_DDTT"			,YdUtils.getCurDate("yyyyMMddHHmmss"));
			sendYDYDJ633.setField("YD_CAR_STOP_LOC"		,szYD_STK_COL_GP);
			sendYDYDJ633.setField("YD_CAR_SCH_ID"			,ydCarSchId);
			sendYDYDJ633.setField("CALL_PGM"			    ,"SANGCHA"); // 입동지시모듈 028전문 전송을 안하게 처리하기 위함
			
			EJBConnector ejbConn = new EJBConnector("default", "CarMvHdSeEJB", this);
			String szRtnMsg = (String) ejbConn.trx("procCarBayInOrdReq", new Class[] { JDTORecord.class }, new Object[] { sendYDYDJ633 });
//			ydDelegate.sendMsg(sendYDYDJ633); 내부전문으로 전송할지는 추후결정
			//----------------------------------------------------------------------------------
			szMsg="차량정지위치[" + szYD_STK_COL_GP + "], 차량스케줄ID[" + ydCarSchId + "] - 차량입동지시요구 모듈을 EJB 호출 성공 - 메세지 : " + szRtnMsg;
			ydSlabUtils.printLog(logId, methodNm, szMsg);
			//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
			
			ydSlabUtils.printLog(logId, methodNm + "차량정지위치[" + szYD_STK_COL_GP + "], 차량스케줄ID[" + ydCarSchId + "] -AB 차량입동지시요구 모듈을 호출", "SL");
			ydSlabUtils.printLog(logId, methodNm, "S-", gdReq);			

			return jrRtn;
			
		} catch(Exception e) {
			throw new DAOException(ydSlabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} //regCarUdWrk
	
	
	
