	    JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
	    JDTORecord params = null;
	    JDTORecordSet queryRst = null;
	    JDTORecord tmp = null;
	    JDTORecord tmp2 = null;
		List aSendMsg = null;
		JDTORecordSet paramSet = null;
		
