				String sYD_AID_WRK_YN = "";
				String sYD_STK_COL_GP = "";
				String sYD_STK_BED_NO = "";
				String sCUST_CD = "";
				String sDEST_CD = "";
				String sCURR_PROG_CD = "";
				String sDETAIL_ARR_CD = "";
				String sSHIP_CD = ""; 
