				String sL_GP = "";
				String sW_GP = "";
				String sTRANS_MEANS_GP = "";
				String sYD_AID_WRK_N_TYPE = ""; // 보조작업 작업방식 : NOT_CUST_TARGET(미지정), CUST_TARGET(지정) 
				
				
				// 차량중심좌표 사용여부
				String sTmp_ANGLE_CAR_YN = "";
				String sTmp_YD_TO_LOC_GUIDE = "";
				String sTmp_YD_AID_WRK_YN = "";
				String sTmp_CUST_CD = "";
				String sTmp_DEST_CD = "";
				String sTmp_CURR_PROG_CD = "";
				String sTmp_DETAIL_ARR_CD = "";
