					// 보조작업 위치지정이 없을 경우 시스템 내부 로직에 의해서 처리한다.
					sTmp_YD_TO_LOC_GUIDE   = ydSlabUtils.trim(gdReq.getHeader("YD_TO_LOC_GUIDE").getValue(i));
