						sYD_STK_COL_GP     = ydSlabUtils.trim(gdReq.getHeader("YD_STK_COL_GP").getValue(i));
						sYD_STK_BED_NO     = ydSlabUtils.trim(gdReq.getHeader("YD_STK_BED_NO").getValue(i));
						sTmp_CUST_CD           = ydSlabUtils.trim(gdReq.getHeader("CUST_CD").getValue(i));
						sTmp_DEST_CD           = ydSlabUtils.trim(gdReq.getHeader("DEST_CD").getValue(i));
						sTmp_CURR_PROG_CD      = ydSlabUtils.trim(gdReq.getHeader("CURR_PROG_CD").getValue(i));
