		if(ydUtils.isEmpty(logId)) logId = ydUtils.getLogIdNew("T");  
		
		szMsg = "["+szOperationName+"] --------------- 메소드 시작 ---------------";
		ydUtils.putLogNew(szClassName, szMethodName, szMsg, YdConstant.DEBUG,logId);
		
		szYD_CAR_SCH_ID			= ydDaoUtils.paraRecChkNull(msgRecord, "YD_CAR_SCH_ID");
		
		rsResult		= JDTORecordFactory.getInstance().createRecordSet("");
		recTemp			= JDTORecordFactory.getInstance().create();
		
		
		szYD_CAR_PROG_STAT		= ydDaoUtils.paraRecChkNull(msgRecord, "YD_CAR_PROG_STAT");
		szYD_CARLD_STOP_LOC		= ydDaoUtils.paraRecChkNull(msgRecord, "YD_CARLD_STOP_LOC");
		szYD_CARLD_WRK_BOOK_ID	= ydDaoUtils.paraRecChkNull(msgRecord, "YD_CARLD_WRK_BOOK_ID");
		szYD_CARUD_STOP_LOC     = ydDaoUtils.paraRecChkNull(msgRecord, "YD_CARUD_STOP_LOC");
		szCAR_NO				= ydDaoUtils.paraRecChkNull(msgRecord, "CAR_NO");
		szCARD_NO				= ydDaoUtils.paraRecChkNull(msgRecord, "CARD_NO");
		
		// 전사물류개선 2021. 1. 6 
		// 취소 차량의 상하차 여부를 판단한다.
		String szCAR_STOP_LOC  = szYD_CARLD_STOP_LOC; // 기본상차셋팅
		String szYD_WBOOK_ID = szYD_CARLD_WRK_BOOK_ID;
